export const FERMENTATION_I18N: Record<string, Record<string, { text?: string; histamineText?: string }>> = {
  kefir: {
    de: { text: "Die Fermentation baut einen Großteil des Laktose ab, daher vertragen manche Menschen Kefir besser als normale Milch – es lohnt sich, deine eigene Grenze bei der Wiedereinführung zu testen.", histamineText: "Da du eine Histaminempfindlichkeit angegeben hast: Dieselbe Fermentation macht Kefir auch reich an Histamin, was für dich möglicherweise wichtiger ist als die Laktose." },
    es: { text: "La fermentación descompone gran parte de la lactosa, por eso algunas personas toleran el kéfir mejor que la leche normal; conviene probar tu propio límite durante la reintroducción.", histamineText: "Como has indicado sensibilidad a la histamina: ten en cuenta que esa misma fermentación también hace que el kéfir sea alto en histamina, lo que puede importarte más que la lactosa." },
    fr: { text: "La fermentation dégrade une grande partie du lactose, si bien que certaines personnes tolèrent mieux le kéfir que le lait ordinaire — cela vaut la peine de tester ta propre limite lors de la réintroduction.", histamineText: "Comme tu as signalé une sensibilité à l'histamine : sache que cette même fermentation rend aussi le kéfir riche en histamine, ce qui peut compter davantage pour toi que le lactose." },
    it: { text: "La fermentazione scompone gran parte del lattosio, per cui alcune persone tollerano il kefir meglio del latte normale: vale la pena testare il tuo limite durante la reintroduzione.", histamineText: "Poiché hai indicato una sensibilità all'istamina: la stessa fermentazione rende il kefir anche ricco di istamina, che per te può contare più del lattosio." },
  },
  yogurt: {
    de: { text: "Joghurt mit lebenden Kulturen ist teilweise fermentiert, daher ist sein Laktosegehalt etwas niedriger als bei Milch. In der Eliminationsphase ist laktosefreier Joghurt dennoch die sicherere Wahl.", histamineText: "Hinweis bei Histaminempfindlichkeit: Fermentierte und gereifte Milchprodukte sind tendenziell reich an Histamin." },
    es: { text: "El yogur con cultivos vivos está parcialmente fermentado, por lo que su lactosa es algo menor que la de la leche. Aun así, el yogur sin lactosa es la opción más segura durante la eliminación.", histamineText: "Nota para la sensibilidad a la histamina: los lácteos fermentados y curados suelen ser altos en histamina." },
    fr: { text: "Le yaourt à ferments vivants est partiellement fermenté, si bien que sa teneur en lactose est un peu plus faible que celle du lait. Le yaourt sans lactose reste toutefois le choix le plus sûr pendant l'élimination.", histamineText: "Remarque en cas de sensibilité à l'histamine : les produits laitiers fermentés et affinés ont tendance à être riches en histamine." },
    it: { text: "Lo yogurt con fermenti vivi è parzialmente fermentato, quindi il suo lattosio è un po' più basso rispetto al latte. Durante l'eliminazione lo yogurt senza lattosio resta comunque la scelta più sicura.", histamineText: "Nota per la sensibilità all'istamina: i latticini fermentati e stagionati tendono a essere ricchi di istamina." },
  },
  sourdough_spelt: {
    de: { text: "Bei der traditionellen Sauerteiggärung verzehren Bakterien den Großteil der Fruktane im Mehl. Deshalb wird Dinkelsauerteig meist vertragen, auch wenn normales Brot Probleme macht – probiere eine normal große Portion aus." },
    es: { text: "La fermentación tradicional con masa madre permite que las bacterias consuman la mayoría de los fructanos de la harina. Por eso la masa madre de espelta suele tolerarse aunque el pan normal no; prueba una ración de tamaño normal y observa." },
    fr: { text: "La fermentation traditionnelle au levain laisse les bactéries consommer la plupart des fructanes de la farine. C'est pourquoi le levain d'épeautre est généralement bien toléré même quand le pain ordinaire ne l'est pas — teste une portion de taille normale." },
    it: { text: "La fermentazione tradizionale con lievito madre permette ai batteri di consumare gran parte dei fruttani della farina. Per questo il lievito madre di farro è di solito tollerato anche quando il pane normale non lo è: prova una porzione di dimensioni normali e osserva." },
  },
  sauerkraut: {
    de: { text: "Eine kleine Portion (etwa 40 g / 2 EL) ist für die meisten Menschen FODMAP-arm genug – erst größere Portionen treiben Fruktane und Mannit zu hoch. Nimm es als Beilage, nicht als Hauptgericht.", histamineText: "Da du eine Histaminempfindlichkeit angegeben hast: Die Fermentation macht Sauerkraut auch sehr reich an Histamin – das kann für dich wichtiger sein als die FODMAPs, selbst bei einer kleinen Portion." },
    es: { text: "Una ración pequeña (unos 40 g / 2 cucharadas) es lo bastante baja en FODMAP para la mayoría; son las raciones más grandes las que elevan demasiado los fructanos y el manitol. Tómalo como guarnición, no como plato principal.", histamineText: "Como has indicado sensibilidad a la histamina: la fermentación también hace que el chucrut sea muy alto en histamina, lo que puede importarte más que los FODMAP, incluso en una ración pequeña." },
    fr: { text: "Une petite portion (environ 40 g / 2 c. à soupe) est assez pauvre en FODMAP pour la plupart des gens — ce sont les portions plus grandes qui font trop grimper les fructanes et le mannitol. Garde-le en accompagnement, pas en plat principal.", histamineText: "Comme tu as signalé une sensibilité à l'histamine : la fermentation rend aussi la choucroute très riche en histamine — cela peut compter davantage pour toi que les FODMAP, même en petite portion." },
    it: { text: "Una piccola porzione (circa 40 g / 2 cucchiai) è abbastanza povera di FODMAP per la maggior parte delle persone: sono le porzioni più grandi a far salire troppo fruttani e mannitolo. Usalo come contorno, non come piatto principale.", histamineText: "Poiché hai indicato una sensibilità all'istamina: la fermentazione rende i crauti anche molto ricchi di istamina, che per te può contare più dei FODMAP, anche in una piccola porzione." },
  },
  kimchi: {
    de: { text: "Eine kleine Portion (etwa 40 g / 2 EL) ist meist in Ordnung – erst größere Portionen sowie der Knoblauch und die Zwiebel, mit denen Kimchi zubereitet wird, treiben die Fruktane zu hoch. Nimm es als Würzbeilage, nicht als Hauptgericht.", histamineText: "Da du eine Histaminempfindlichkeit angegeben hast: Die Fermentation macht Kimchi auch sehr reich an Histamin – das kann für dich wichtiger sein als die FODMAPs, selbst bei einer kleinen Portion." },
    es: { text: "Una ración pequeña (unos 40 g / 2 cucharadas) suele estar bien; son las raciones más grandes, junto con el ajo y la cebolla con que se elabora el kimchi, lo que eleva demasiado los fructanos. Tómalo como condimento, no como plato principal.", histamineText: "Como has indicado sensibilidad a la histamina: la fermentación también hace que el kimchi sea muy alto en histamina, lo que puede importarte más que los FODMAP, incluso en una ración pequeña." },
    fr: { text: "Une petite portion (environ 40 g / 2 c. à soupe) convient généralement — ce sont les portions plus grandes, ainsi que l'ail et l'oignon avec lesquels le kimchi est préparé, qui font trop grimper les fructanes. Garde-le comme condiment, pas comme plat principal.", histamineText: "Comme tu as signalé une sensibilité à l'histamine : la fermentation rend aussi le kimchi très riche en histamine — cela peut compter davantage pour toi que les FODMAP, même en petite portion." },
    it: { text: "Una piccola porzione (circa 40 g / 2 cucchiai) di solito va bene: sono le porzioni più grandi, oltre all'aglio e alla cipolla con cui si prepara il kimchi, a far salire troppo i fruttani. Usalo come condimento, non come piatto principale.", histamineText: "Poiché hai indicato una sensibilità all'istamina: la fermentazione rende il kimchi anche molto ricco di istamina, che per te può contare più dei FODMAP, anche in una piccola porzione." },
  },
  cheddar: {
    de: { text: "Hart gereifte Käse wie Cheddar sind sehr laktosearm – der Reifeprozess baut sie ab –, daher sind sie in normalen Portionen FODMAP-arm.", histamineText: "Bei Histaminempfindlichkeit gilt jedoch: Je länger ein Käse reift, desto höher sein Histamin. Gereifte Käse sind ein häufiger Histaminauslöser." },
    es: { text: "Los quesos curados duros como el cheddar tienen muy poca lactosa —el proceso de curación la descompone—, por lo que son bajos en FODMAP en raciones normales.", histamineText: "Sin embargo, para la sensibilidad a la histamina: cuanto más se cura un queso, más histamina tiene. Los quesos curados son un desencadenante habitual de histamina." },
    fr: { text: "Les fromages à pâte dure affinés comme le cheddar sont très pauvres en lactose — l'affinage le dégrade — ils sont donc pauvres en FODMAP dans des portions normales.", histamineText: "En cas de sensibilité à l'histamine toutefois : plus un fromage est affiné, plus il est riche en histamine. Les fromages affinés sont un déclencheur fréquent." },
    it: { text: "I formaggi stagionati a pasta dura come il cheddar hanno pochissimo lattosio — la stagionatura lo scompone — quindi sono a basso contenuto di FODMAP in porzioni normali.", histamineText: "Per la sensibilità all'istamina però: più a lungo un formaggio stagiona, più istamina contiene. I formaggi stagionati sono un fattore scatenante comune." },
  },
  parmesan: {
    de: { text: "Parmesan reift lange genug, dass fast keine Laktose mehr übrig ist – er ist in normalen Portionen FODMAP-arm.", histamineText: "Bei Histaminempfindlichkeit: Lang gereifte Käse wie Parmesan gehören zu den histaminreichsten Lebensmitteln." },
    es: { text: "El parmesano se cura el tiempo suficiente para que casi no quede lactosa; es bajo en FODMAP en raciones normales.", histamineText: "Para la sensibilidad a la histamina: los quesos muy curados como el parmesano están entre los alimentos con más histamina." },
    fr: { text: "Le parmesan est affiné assez longtemps pour qu'il ne reste presque plus de lactose — il est pauvre en FODMAP dans des portions normales.", histamineText: "En cas de sensibilité à l'histamine : les fromages longuement affinés comme le parmesan comptent parmi les aliments les plus riches en histamine." },
    it: { text: "Il parmigiano è stagionato abbastanza a lungo da non lasciare quasi lattosio: è a basso contenuto di FODMAP in porzioni normali.", histamineText: "Per la sensibilità all'istamina: i formaggi a lunga stagionatura come il parmigiano sono tra gli alimenti più ricchi di istamina." },
  },
  salami: {
    de: { text: "Salami variiert stark: Viele werden mit Knoblauch und Zwiebel hergestellt (reich an Fruktanen). Reine Salami ist FODMAP-arm, aber prüfe die Zutatenliste – oder teste deine Verträglichkeit mit einer kleinen Menge." },
    es: { text: "El salami varía mucho: muchos llevan ajo y cebolla (ricos en fructanos). El salami sin más es bajo en FODMAP, pero revisa la etiqueta o prueba tu tolerancia con una cantidad pequeña." },
    fr: { text: "Le salami varie beaucoup : beaucoup sont préparés avec de l'ail et de l'oignon (riches en fructanes). Le salami nature est pauvre en FODMAP, mais vérifie l'étiquette — ou teste ta tolérance avec une petite quantité." },
    it: { text: "Il salame varia molto: molti sono preparati con aglio e cipolla (ricchi di fruttani). Il salame semplice è a basso contenuto di FODMAP, ma controlla l'etichetta — o testa la tua tolleranza con una piccola quantità." },
  },
};

