// { [recipeId]: { [lang]: { title?: string; steps?: string } } }
export const RECIPES_I18N: Record<string, Record<string, { title?: string; steps?: string }>> = {
  r1: {
    de: { title: "Blaubeer-Haferbrei", steps: "Bringe 50 g Haferflocken mit 200 ml Mandelmilch bei mittlerer Hitze zum leichten Köcheln und rühre etwa 5 Minuten häufig um, damit nichts ansetzt, bis der Brei dick und cremig ist. Nimm ihn vom Herd und lass ihn eine Minute nachziehen. In eine Schale füllen und mit einer kleinen Handvoll Blaubeeren und einem Schuss Ahornsirup toppen. Bleib bei etwa 50 g trockenen Haferflocken – eine größere Portion erhöht die Fruktane." },
    es: { title: "Gachas de avena con arándanos", steps: "Lleva 50 g de avena y 200 ml de leche de almendras a fuego medio hasta que hierva suavemente, removiendo a menudo para que no se pegue, unos 5 minutos hasta que quede espesa y cremosa. Retira del fuego y deja reposar un minuto para que espese. Sirve en un bol y añade un puñado pequeño de arándanos y un chorrito de sirope de arce. Mantén la avena en unos 50 g en seco para que siga siendo baja en FODMAP." },
    fr: { title: "Porridge d'avoine aux myrtilles", steps: "Porte 50 g de flocons d'avoine et 200 ml de lait d'amande à frémissement à feu moyen, en remuant souvent pour éviter que ça n'attache, pendant environ 5 minutes jusqu'à obtenir une texture épaisse et crémeuse. Retire du feu et laisse reposer une minute pour épaissir. Verse dans un bol et garnis d'une petite poignée de myrtilles et d'un filet de sirop d'érable. Reste autour de 50 g d'avoine sèche pour rester pauvre en FODMAP." },
    it: { title: "Porridge di avena ai mirtilli", steps: "Porta 50 g di fiocchi d'avena e 200 ml di latte di mandorla a un leggero sobbollire a fuoco medio, mescolando spesso perché non si attacchi, per circa 5 minuti finché diventa denso e cremoso. Togli dal fuoco e lascia riposare un minuto per addensare. Versa in una ciotola e completa con una piccola manciata di mirtilli e un filo di sciroppo d'acero. Resta sui 50 g di avena secca per mantenerlo a basso contenuto di FODMAP." },
  },
  r2: {
    de: { title: "Rührei auf glutenfreiem Toast", steps: "Verquirle 2 Eier mit einer Prise Salz. Lass ein Stück Butter in einer beschichteten Pfanne bei niedriger bis mittlerer Hitze schmelzen, gib die Eier hinein und rühre sanft mit einem Spatel, bis sie gerade gestockt, aber noch weich und cremig sind. Toaste währenddessen zwei Scheiben glutenfreies Brot und bestreiche sie dünn mit Butter. Verteile das Rührei darauf und serviere mit ein paar Scheiben frischer Tomate." },
    es: { title: "Huevos revueltos sobre tostada sin gluten", steps: "Bate 2 huevos con una pizca de sal. Derrite un poco de mantequilla en una sartén antiadherente a fuego medio-bajo, echa los huevos y remueve con suavidad con una espátula hasta que cuajen pero sigan blandos y cremosos. Mientras, tuesta dos rebanadas de pan sin gluten y úntalas ligeramente con mantequilla. Coloca los huevos encima y sirve con unas rodajas de tomate fresco." },
    fr: { title: "Œufs brouillés sur toast sans gluten", steps: "Bats 2 œufs avec une pincée de sel. Fais fondre une noix de beurre dans une poêle antiadhésive à feu doux-moyen, verse les œufs et remue doucement à la spatule jusqu'à ce qu'ils soient juste pris mais encore moelleux et crémeux. Pendant ce temps, fais griller deux tranches de pain sans gluten et beurre-les légèrement. Dépose les œufs dessus et sers avec quelques tranches de tomate fraîche." },
    it: { title: "Uova strapazzate su pane senza glutine", steps: "Sbatti 2 uova con un pizzico di sale. Sciogli una noce di burro in una padella antiaderente a fuoco medio-basso, versa le uova e mescola delicatamente con una spatola finché sono appena rapprese ma ancora morbide e cremose. Nel frattempo tosta due fette di pane senza glutine e spalmale con un velo di burro. Distribuisci sopra le uova e servi con qualche fetta di pomodoro fresco." },
  },
  r3: {
    de: { title: "Laktosefreie Joghurtbowl", steps: "Gib eine großzügige Portion laktosefreien Joghurt in eine Schale. Entkelche und halbiere eine kleine Handvoll Erdbeeren und verteile sie darüber. Streue 1 Esslöffel Chiasamen und ein paar gehackte Walnüsse für den Biss darauf. Lass alles ein paar Minuten stehen, damit die Chiasamen leicht aufquellen, bevor du isst." },
    es: { title: "Bol de yogur sin lactosa", steps: "Pon una ración generosa de yogur sin lactosa en un bol. Quita el rabito y parte por la mitad un puñado pequeño de fresas y repártelas por encima. Espolvorea 1 cucharada de semillas de chía y unas nueces picadas para dar un toque crujiente. Deja reposar un par de minutos para que la chía se ablande un poco antes de comer." },
    fr: { title: "Bol de yaourt sans lactose", steps: "Verse une bonne portion de yaourt sans lactose dans un bol. Équeute et coupe en deux une petite poignée de fraises et répartis-les dessus. Parsème d'1 cuillère à soupe de graines de chia et de quelques noix concassées pour le croquant. Laisse reposer deux minutes pour que le chia ramollisse légèrement avant de déguster." },
    it: { title: "Coppa di yogurt senza lattosio", steps: "Metti una porzione abbondante di yogurt senza lattosio in una ciotola. Priva del picciolo e taglia a metà una piccola manciata di fragole e distribuiscile sopra. Cospargi con 1 cucchiaio di semi di chia e qualche gheriglio di noce tritato per croccantezza. Lascia riposare un paio di minuti così i semi di chia si ammorbidiscono leggermente prima di mangiare." },
  },
  r4: {
    de: { title: "Smoothie mit fester Banane", steps: "Schäle eine feste (unreife) Banane und brich sie in Stücke. Mixe sie mit 200 ml Mandelmilch, 1 Esslöffel Chiasamen und einem Schuss Ahornsirup, bis alles glatt ist. Gib ein paar Eiswürfel dazu und mixe erneut für eine kältere, dickere Konsistenz. Nimm eine feste statt einer sehr reifen Banane – so bleibt der Smoothie FODMAP-arm." },
    es: { title: "Batido de plátano firme", steps: "Pela un plátano firme (verde) y pártelo en trozos. Bátelo con 200 ml de leche de almendras, 1 cucharada de semillas de chía y un chorrito de sirope de arce hasta que quede homogéneo. Añade un par de cubitos de hielo y vuelve a batir para una textura más fría y espesa. Usa un plátano firme en lugar de uno muy maduro: así el batido se mantiene bajo en FODMAP." },
    fr: { title: "Smoothie à la banane ferme", steps: "Épluche une banane ferme (peu mûre) et casse-la en morceaux. Mixe-la avec 200 ml de lait d'amande, 1 cuillère à soupe de graines de chia et un filet de sirop d'érable jusqu'à obtenir une texture lisse. Ajoute quelques glaçons et mixe à nouveau pour une texture plus froide et épaisse. Utilise une banane ferme plutôt que très mûre : le smoothie reste pauvre en FODMAP." },
    it: { title: "Frullato di banana soda", steps: "Sbuccia una banana soda (acerba) e spezzala a pezzi. Frullala con 200 ml di latte di mandorla, 1 cucchiaio di semi di chia e un filo di sciroppo d'acero fino a ottenere un composto liscio. Aggiungi un paio di cubetti di ghiaccio e frulla di nuovo per una consistenza più fredda e densa. Usa una banana soda invece di una molto matura: così il frullato resta a basso contenuto di FODMAP." },
  },
  r5: {
    de: { title: "Buchweizen-Pfannkuchen", steps: "Verrühre 100 g Buchweizenmehl mit 1 Ei und so viel Mandelmilch, dass ein glatter, gießfähiger Teig entsteht. Erhitze eine leicht geölte beschichtete Pfanne bei mittlerer Hitze und gib kleine Teigkreise hinein. Backe, bis sich an der Oberfläche Bläschen bilden, wende dann und backe die andere Seite goldbraun. Staple die Pfannkuchen und toppe sie mit Ahornsirup und einer Handvoll Blaubeeren." },
    es: { title: "Tortitas de trigo sarraceno", steps: "Mezcla 100 g de harina de trigo sarraceno con 1 huevo y la leche de almendras necesaria para lograr una masa suave y que se pueda verter. Calienta una sartén antiadherente ligeramente engrasada a fuego medio y vierte pequeños círculos de masa. Cocina hasta que salgan burbujas en la superficie, dales la vuelta y dora el otro lado. Apila las tortitas y cúbrelas con sirope de arce y un puñado de arándanos." },
    fr: { title: "Pancakes au sarrasin", steps: "Mélange 100 g de farine de sarrasin avec 1 œuf et assez de lait d'amande pour obtenir une pâte lisse et coulante. Chauffe une poêle antiadhésive légèrement huilée à feu moyen et verse de petits ronds de pâte. Cuis jusqu'à ce que des bulles se forment en surface, puis retourne et cuis l'autre côté jusqu'à ce qu'il soit doré. Empile les pancakes et garnis de sirop d'érable et d'une poignée de myrtilles." },
    it: { title: "Pancake di grano saraceno", steps: "Mescola 100 g di farina di grano saraceno con 1 uovo e latte di mandorla quanto basta per ottenere una pastella liscia e fluida. Scalda una padella antiaderente leggermente unta a fuoco medio e versa piccoli dischi di pastella. Cuoci finché in superficie si formano delle bollicine, poi gira e cuoci l'altro lato fino a doratura. Impila i pancake e completa con sciroppo d'acero e una manciata di mirtilli." },
  },
  r6: {
    de: { title: "Spinat-Feta-Omelett", steps: "Brate bis zu 75 g Babyspinat in etwas Olivenöl an, bis er gerade zusammenfällt, und stell ihn beiseite. Verquirle 2 Eier mit einer Prise Salz und gib sie in dieselbe Pfanne bei mittlerer Hitze. Sobald der Boden stockt, verteile Spinat und zerbröckelten Feta auf einer Hälfte. Klappe das Omelett über die Füllung und lass es auf einen Teller gleiten." },
    es: { title: "Tortilla de espinacas y feta", steps: "Saltea hasta 75 g de espinacas baby en un poco de aceite de oliva hasta que se ablanden, y resérvalas. Bate 2 huevos con una pizca de sal y viértelos en la misma sartén a fuego medio. Cuando cuaje la base, reparte las espinacas y el feta desmenuzado sobre una mitad. Dobla la tortilla sobre el relleno y pásala a un plato." },
    fr: { title: "Omelette épinards et feta", steps: "Fais revenir jusqu'à 75 g de pousses d'épinard dans un peu d'huile d'olive jusqu'à ce qu'elles soient tout juste fondues, puis réserve. Bats 2 œufs avec une pincée de sel et verse-les dans la même poêle à feu moyen. Dès que le dessous est pris, répartis les épinards et la feta émiettée sur une moitié. Replie l'omelette sur la garniture et fais-la glisser dans une assiette." },
    it: { title: "Omelette con spinaci e feta", steps: "Salta fino a 75 g di spinacini in un po' di olio d'oliva finché sono appena appassiti, poi mettili da parte. Sbatti 2 uova con un pizzico di sale e versale nella stessa padella a fuoco medio. Quando la base si rapprende, distribuisci gli spinaci e la feta sbriciolata su metà. Piega l'omelette sul ripieno e falla scivolare su un piatto." },
  },
  r7: {
    de: { title: "Haferbrei mit Kiwi", steps: "Erwärme 50 g Haferflocken in 200 ml Mandelmilch bei niedriger Hitze einige Minuten, bis sie weich und cremig sind. Fülle alles in eine Schale und lass es kurz abkühlen. Schäle und schneide eine Kiwi und lege die Scheiben darauf. Zum Schluss mit Kürbiskernen für den Biss bestreuen." },
    es: { title: "Copos de avena con kiwi", steps: "Calienta 50 g de avena en 200 ml de leche de almendras a fuego bajo durante unos minutos hasta que estén suaves y cremosos. Pásalo a un bol y deja que se enfríe un poco. Pela y corta un kiwi y coloca las rodajas por encima. Termina con unas pipas de calabaza para dar un toque crujiente." },
    fr: { title: "Flocons d'avoine au kiwi", steps: "Fais chauffer 50 g de flocons d'avoine dans 200 ml de lait d'amande à feu doux quelques minutes jusqu'à ce qu'ils soient moelleux et crémeux. Verse dans un bol et laisse tiédir légèrement. Épluche et coupe un kiwi et dispose les rondelles dessus. Termine par une poignée de graines de courge pour le croquant." },
    it: { title: "Fiocchi d'avena con kiwi", steps: "Scalda 50 g di fiocchi d'avena in 200 ml di latte di mandorla a fuoco basso per qualche minuto finché sono morbidi e cremosi. Versa in una ciotola e lascia intiepidire leggermente. Sbuccia e affetta un kiwi e disponi le fette sopra. Completa con una spolverata di semi di zucca per croccantezza." },
  },
  r8: {
    de: { title: "Chia-Pudding", steps: "Rühre 3 Esslöffel Chiasamen mit 200 ml Mandelmilch und einem Schuss Ahornsirup glatt. Decke alles ab und stelle es über Nacht (oder mindestens 4 Stunden) in den Kühlschrank, damit die Samen zu einem Pudding aufquellen. Rühre vor dem Servieren noch einmal kräftig um, um Klümpchen aufzulösen. Mit einer kleinen Handvoll Himbeeren toppen." },
    es: { title: "Pudin de chía", steps: "Mezcla 3 cucharadas de semillas de chía con 200 ml de leche de almendras y un chorrito de sirope de arce hasta que quede homogéneo. Tápalo y déjalo en la nevera toda la noche, o al menos 4 horas, para que las semillas se hinchen y formen un pudin. Remueve bien antes de servir para deshacer los grumos. Cubre con un puñado pequeño de frambuesas." },
    fr: { title: "Pudding de chia", steps: "Mélange 3 cuillères à soupe de graines de chia avec 200 ml de lait d'amande et un filet de sirop d'érable jusqu'à obtenir un mélange homogène. Couvre et place au réfrigérateur toute la nuit, ou au moins 4 heures, pour que les graines gonflent en pudding. Remue bien avant de servir pour défaire les grumeaux. Garnis d'une petite poignée de framboises." },
    it: { title: "Budino di chia", steps: "Mescola 3 cucchiai di semi di chia con 200 ml di latte di mandorla e un filo di sciroppo d'acero fino a ottenere un composto omogeneo. Copri e metti in frigorifero per tutta la notte, o almeno 4 ore, così i semi si gonfiano in un budino. Mescola bene prima di servire per sciogliere eventuali grumi. Completa con una piccola manciata di lamponi." },
  },
  r9: {
    de: { title: "Avocado-Brot", steps: "Zerdrücke etwa 30 g Avocado mit einem Spritzer Zitronensaft, einer Prise Salz und etwas Olivenöl. Toaste eine Scheibe glutenfreies Brot knusprig. Streiche die Avocado gleichmäßig darauf und beträufle sie zum Schluss mit Olivenöl. Bleib bei etwa 30 g Avocado, damit es FODMAP-arm bleibt." },
    es: { title: "Tostada de aguacate", steps: "Machaca unos 30 g de aguacate con un chorrito de zumo de limón, una pizca de sal y un poco de aceite de oliva. Tuesta una rebanada de pan sin gluten hasta que quede crujiente. Extiende el aguacate por encima de manera uniforme y termina con un último chorrito de aceite de oliva. No pases de unos 30 g de aguacate para que siga siendo bajo en FODMAP." },
    fr: { title: "Toast à l'avocat", steps: "Écrase environ 30 g d'avocat avec un filet de jus de citron, une pincée de sel et un peu d'huile d'olive. Fais griller une tranche de pain sans gluten jusqu'à ce qu'elle soit croustillante. Étale l'avocat uniformément dessus et termine par un dernier filet d'huile d'olive. Reste autour de 30 g d'avocat pour que ça reste pauvre en FODMAP." },
    it: { title: "Toast all'avocado", steps: "Schiaccia circa 30 g di avocado con una spruzzata di succo di limone, un pizzico di sale e un po' di olio d'oliva. Tosta una fetta di pane senza glutine finché è croccante. Spalma l'avocado in modo uniforme sopra e completa con un ultimo filo di olio d'oliva. Resta intorno ai 30 g di avocado per mantenerlo a basso contenuto di FODMAP." },
  },
  r10: {
    de: { title: "Quinoa-Frühstücksbowl", steps: "Spüle 50 g Quinoa gründlich ab und köchle sie in 200 ml Mandelmilch etwa 12–15 Minuten, bis sie weich ist und die Flüssigkeit fast aufgesogen ist. Fülle alles in eine Schale und lass es kurz abkühlen. Toppe mit einer Handvoll Blaubeeren und ein paar gehackten Walnüssen. Zum Schluss mit Ahornsirup beträufeln." },
    es: { title: "Bol de desayuno con quinoa", steps: "Enjuaga bien 50 g de quinoa y cuécela a fuego lento en 200 ml de leche de almendras unos 12–15 minutos hasta que esté tierna y se absorba casi todo el líquido. Pásala a un bol y deja que se enfríe un poco. Cubre con un puñado de arándanos y unas nueces picadas. Termina con un chorrito de sirope de arce." },
    fr: { title: "Bol de quinoa du matin", steps: "Rince bien 50 g de quinoa, puis fais-le mijoter dans 200 ml de lait d'amande environ 12 à 15 minutes jusqu'à ce qu'il soit tendre et que presque tout le liquide soit absorbé. Verse dans un bol et laisse tiédir légèrement. Garnis d'une poignée de myrtilles et de quelques noix concassées. Termine par un filet de sirop d'érable." },
    it: { title: "Ciotola di quinoa per colazione", steps: "Sciacqua bene 50 g di quinoa, poi falla sobbollire in 200 ml di latte di mandorla per circa 12–15 minuti finché è tenera e quasi tutto il liquido è assorbito. Versa in una ciotola e lascia intiepidire leggermente. Completa con una manciata di mirtilli e qualche gheriglio di noce tritato. Finisci con un filo di sciroppo d'acero." },
  },
  r11: {
    de: { title: "Weich gekochte Eier auf Reis", steps: "Lass 2 Eier in leicht kochendes Wasser gleiten und koche sie 6 Minuten für ein weiches, flüssiges Eigelb, schrecke sie kurz unter kaltem Wasser ab und pelle sie vorsichtig. Erwärme eine Schale gekochten Reis. Halbiere die Eier über dem Reis und beträufle alles mit etwas Sojasauce. Serviere, solange noch alles warm ist." },
    es: { title: "Huevos pasados por agua con arroz", steps: "Introduce 2 huevos en agua hirviendo suavemente y cuécelos 6 minutos para una yema blanda y líquida; refréscalos un momento bajo agua fría y pélalos con cuidado. Calienta un bol de arroz cocido. Parte los huevos por la mitad sobre el arroz y termina con un chorrito de salsa de soja. Sirve mientras todo sigue caliente." },
    fr: { title: "Œufs mollets et riz", steps: "Plonge 2 œufs dans une eau à léger frémissement et fais-les cuire 6 minutes pour un jaune coulant, puis rafraîchis-les un instant sous l'eau froide et écale-les délicatement. Réchauffe un bol de riz cuit. Coupe les œufs en deux sur le riz et termine par un trait de sauce soja. Sers tant que tout est encore chaud." },
    it: { title: "Uova alla coque con riso", steps: "Cala 2 uova in acqua che sobbolle appena e cuocile 6 minuti per un tuorlo morbido e colante, poi raffreddale un momento sotto l'acqua fredda e sgusciale con delicatezza. Scalda una ciotola di riso cotto. Taglia le uova a metà sul riso e completa con un goccio di salsa di soia. Servi finché è tutto ancora caldo." },
  },
  r12: {
    de: { title: "Joghurt mit Ananas", steps: "Gib laktosefreien Joghurt in ein Glas oder eine Schale. Schneide frische Ananas in kleine Stücke und schichte sie auf den Joghurt. Streue etwas Chia zwischen die Schichten und füge nach Belieben eine zweite Schicht hinzu. Iss es gleich, solange die Ananas noch saftig ist." },
    es: { title: "Yogur con piña", steps: "Pon yogur sin lactosa en un vaso o bol. Corta piña fresca en trozos pequeños y colócala en capas sobre el yogur. Espolvorea un poco de chía entre las capas y añade una segunda capa si quieres. Cómelo enseguida, mientras la piña sigue jugosa." },
    fr: { title: "Yaourt à l'ananas", steps: "Verse du yaourt sans lactose dans un verre ou un bol. Coupe de l'ananas frais en petits morceaux et dispose-les en couches sur le yaourt. Parsème un peu de chia entre les couches et ajoute une deuxième couche si tu veux. Déguste tout de suite, tant que l'ananas est encore juteux." },
    it: { title: "Yogurt e ananas", steps: "Metti dello yogurt senza lattosio in un bicchiere o in una ciotola. Taglia l'ananas fresco a pezzetti e disponilo a strati sullo yogurt. Cospargi un po' di chia tra gli strati e aggiungi un secondo strato se vuoi. Mangialo subito, finché l'ananas è ancora succoso." },
  },
  r13: {
    de: { title: "Hähnchen-Reis-Bowl", steps: "Koche den Reis und halte ihn warm. Schneide eine Hähnchenbrust in Streifen und brate sie in Olivenöl bei mittlerer bis hoher Hitze goldbraun und gar, etwa 6–8 Minuten. Reibe die Karotte und schneide die Gurke in dünne Scheiben. Häufe Hähnchen und Gemüse auf den Reis und beträufle alles mit Sojasauce." },
    es: { title: "Bol de pollo y arroz", steps: "Cuece el arroz y mantenlo caliente. Corta una pechuga de pollo en tiras y sofríela en aceite de oliva a fuego medio-alto hasta que esté dorada y hecha, unos 6–8 minutos. Ralla la zanahoria y corta el pepino en rodajas finas. Coloca el pollo y las verduras sobre el arroz y termina con un chorrito de salsa de soja." },
    fr: { title: "Bol poulet et riz", steps: "Cuis le riz et garde-le au chaud. Coupe un blanc de poulet en lamelles et fais-le revenir dans l'huile d'olive à feu moyen-vif jusqu'à ce qu'il soit doré et cuit, environ 6 à 8 minutes. Râpe la carotte et coupe le concombre en fines rondelles. Dispose le poulet et les légumes sur le riz et termine par un trait de sauce soja." },
    it: { title: "Bowl di pollo e riso", steps: "Cuoci il riso e tienilo al caldo. Taglia un petto di pollo a strisce e rosolalo in olio d'oliva a fuoco medio-alto finché è dorato e cotto, circa 6–8 minuti. Grattugia la carota e affetta il cetriolo sottilmente. Disponi pollo e verdure sul riso e completa con un goccio di salsa di soia." },
  },
  r14: {
    de: { title: "Thunfisch-Kartoffel-Salat", steps: "Koche gewürfelte Kartoffeln in etwa 12–15 Minuten gerade weich, gieße sie ab und lass sie abkühlen. Lass eine Dose Thunfisch abtropfen und zerpflücke ihn in eine Schüssel. Gib die Kartoffeln, einen Löffel Mayonnaise, etwas Senf und gewürfelte Gurke dazu und hebe alles vorsichtig unter. Abschmecken und kühl servieren." },
    es: { title: "Ensalada de atún y patata", steps: "Cuece las patatas en dados hasta que estén tiernas, unos 12–15 minutos, escúrrelas y déjalas enfriar. Escurre una lata de atún y desmenúzalo en un bol. Añade las patatas, una cucharada de mayonesa, un poco de mostaza y algo de pepino en dados, y mézclalo todo con cuidado. Rectifica de sal y sirve fresco." },
    fr: { title: "Salade de thon et pommes de terre", steps: "Fais cuire des pommes de terre en dés jusqu'à ce qu'elles soient juste tendres, environ 12 à 15 minutes, puis égoutte-les et laisse-les refroidir. Égoutte une boîte de thon et émiette-le dans un saladier. Ajoute les pommes de terre, une cuillère de mayonnaise, un peu de moutarde et du concombre en dés, et mélange délicatement. Assaisonne et sers frais." },
    it: { title: "Insalata di tonno e patate", steps: "Lessa le patate a cubetti finché sono appena tenere, circa 12–15 minuti, poi scolale e falle raffreddare. Scola una scatoletta di tonno e sminuzzalo in una ciotola. Aggiungi le patate, un cucchiaio di maionese, un po' di senape e del cetriolo a dadini, e amalgama tutto delicatamente. Aggiusta di sale e servi fresco." },
  },
  r15: {
    de: { title: "Quinoa-Salat mit Feta", steps: "Koche die Quinoa und breite sie zum Abkühlen auf einem Teller aus. Gib sie in eine Schüssel mit zerbröckeltem Feta, gewürfelter Gurke und halbierten Kirschtomaten (bis zu 75 g). Mit Olivenöl und einem kräftigen Spritzer Zitrone anmachen und durchmengen. Vor dem Servieren mit Salz und Pfeffer würzen." },
    es: { title: "Ensalada de quinoa con feta", steps: "Cuece la quinoa y extiéndela en un plato para que se enfríe. Ponla en un bol con feta desmenuzado, pepino en dados y tomates cherry por la mitad (hasta 75 g). Aliña con aceite de oliva y un buen chorro de limón, y mezcla. Salpimenta antes de servir." },
    fr: { title: "Salade de quinoa à la feta", steps: "Cuis le quinoa, puis étale-le sur une assiette pour le refroidir. Verse-le dans un saladier avec de la feta émiettée, du concombre en dés et des tomates cerises coupées en deux (jusqu'à 75 g). Assaisonne d'huile d'olive et d'un bon filet de citron, puis mélange. Sale et poivre avant de servir." },
    it: { title: "Insalata di quinoa con feta", steps: "Cuoci la quinoa, poi stendila su un piatto per farla raffreddare. Versala in una ciotola con feta sbriciolata, cetriolo a dadini e pomodorini tagliati a metà (fino a 75 g). Condisci con olio d'oliva e una bella spruzzata di limone e mescola. Aggiusta di sale e pepe prima di servire." },
  },
  r16: {
    de: { title: "Salatwraps mit Garnelen", steps: "Reibe etwas frischen Ingwer und brate die Garnelen damit in einer heißen Pfanne mit einem Schuss Sojasauce, bis sie rosa und gerade gar sind, 2–3 Minuten. Löse ganze Salatblätter als Schälchen ab. Fülle die Garnelen in die Blätter und toppe sie mit geraspelter Karotte. Sofort servieren, solange sie warm sind." },
    es: { title: "Wraps de lechuga con gambas", steps: "Ralla un poco de jengibre fresco y saltea las gambas con él en una sartén caliente con un chorrito de soja hasta que estén rosadas y hechas, 2–3 minutos. Separa hojas enteras de lechuga para usarlas como cuencos. Reparte las gambas en las hojas y cúbrelas con zanahoria rallada. Sirve enseguida, mientras están calientes." },
    fr: { title: "Wraps de laitue aux crevettes", steps: "Râpe un peu de gingembre frais et fais sauter les crevettes avec dans une poêle chaude avec un trait de soja jusqu'à ce qu'elles soient roses et juste cuites, 2 à 3 minutes. Détache des feuilles entières de laitue pour en faire des coupelles. Répartis les crevettes dans les feuilles et garnis de carotte râpée. Sers aussitôt, tant que c'est chaud." },
    it: { title: "Involtini di lattuga con gamberi", steps: "Grattugia un po' di zenzero fresco e salta i gamberi con quello in una padella calda con un goccio di soia finché sono rosati e appena cotti, 2–3 minuti. Stacca foglie intere di lattuga da usare come coppette. Distribuisci i gamberi nelle foglie e completa con carota grattugiata. Servi subito, finché sono caldi." },
  },
  r17: {
    de: { title: "Pute-Reisnudel-Bowl", steps: "Koche die Reisnudeln nach Packungsangabe, gieße sie ab und spüle sie kurz. Brate die Pute in knoblaucharomatisiertem Öl bei mittlerer bis hoher Hitze gar. Schneide Karotte und Gurke in feine Streifen. Vermenge die Nudeln mit der Pute und dem Gemüse und beträufle alles mit Sojasauce." },
    es: { title: "Bol de pavo con fideos de arroz", steps: "Cuece los fideos de arroz según el paquete, escúrrelos y enjuágalos. Sofríe el pavo en aceite con infusión de ajo a fuego medio-alto hasta que esté hecho. Corta la zanahoria y el pepino en tiras finas. Mezcla los fideos con el pavo y las verduras y termina con salsa de soja." },
    fr: { title: "Bol de dinde aux nouilles de riz", steps: "Cuis les nouilles de riz selon le paquet, puis égoutte-les et rince-les. Fais revenir la dinde dans de l'huile à l'ail à feu moyen-vif jusqu'à ce qu'elle soit cuite. Coupe la carotte et le concombre en fines lamelles. Mélange les nouilles avec la dinde et les légumes et termine par de la sauce soja." },
    it: { title: "Bowl di tacchino e noodle di riso", steps: "Cuoci i noodle di riso come da confezione, poi scolali e sciacquali. Rosola il tacchino in olio aromatizzato all'aglio a fuoco medio-alto finché è cotto. Taglia carota e cetriolo a listarelle sottili. Mescola i noodle con il tacchino e le verdure e completa con salsa di soia." },
  },
  r18: {
    de: { title: "Tomate-Mozzarella-Teller", steps: "Schneide frische Tomate (bis zu 65 g pro Portion) und richte sie mit Mozzarella-Scheiben auf einem Teller an. Großzügig mit Olivenöl beträufeln und einen Löffel Basilikumpesto dazugeben. Mit etwas Salz und Pfeffer würzen. Bei Zimmertemperatur servieren – so schmeckt es am besten." },
    es: { title: "Plato de tomate y mozzarella", steps: "Corta tomate fresco (hasta 65 g por ración) y disponlo en un plato con lonchas de mozzarella. Riega generosamente con aceite de oliva y añade una cucharada de pesto de albahaca. Salpimenta ligeramente. Sirve a temperatura ambiente para que sepa mejor." },
    fr: { title: "Assiette tomate-mozzarella", steps: "Coupe de la tomate fraîche (jusqu'à 65 g par portion) et dispose-la dans une assiette avec des tranches de mozzarella. Arrose généreusement d'huile d'olive et ajoute une cuillère de pesto au basilic. Sale et poivre légèrement. Sers à température ambiante pour plus de saveur." },
    it: { title: "Piatto di pomodoro e mozzarella", steps: "Affetta pomodoro fresco (fino a 65 g a porzione) e disponilo su un piatto con fette di mozzarella. Condisci generosamente con olio d'oliva e aggiungi un cucchiaio di pesto al basilico. Regola con un po' di sale e pepe. Servi a temperatura ambiente per esaltarne il sapore." },
  },
  r19: {
    de: { title: "Lachs mit Quinoa", steps: "Heize den Ofen auf 200 °C vor. Lege den Lachs auf ein ausgelegtes Blech, beträufle ihn mit Olivenöl und einem Spritzer Zitrone und backe ihn etwa 12 Minuten, bis er sich leicht zerteilen lässt. Koche währenddessen die Quinoa und lass den Spinat in einer heißen Pfanne zusammenfallen. Serviere den Lachs auf der Quinoa mit dem Spinat daneben." },
    es: { title: "Salmón con quinoa", steps: "Precalienta el horno a 200 °C. Coloca el salmón en una bandeja forrada, riégalo con aceite de oliva y un chorro de limón y hornéalo unos 12 minutos hasta que se desmenuce con facilidad. Mientras, cuece la quinoa y saltea las espinacas en una sartén caliente hasta que se ablanden. Sirve el salmón sobre la quinoa con las espinacas al lado." },
    fr: { title: "Saumon et quinoa", steps: "Préchauffe le four à 200 °C. Dépose le saumon sur une plaque chemisée, arrose-le d'huile d'olive et d'un filet de citron et enfourne environ 12 minutes jusqu'à ce qu'il se détache facilement. Pendant ce temps, cuis le quinoa et fais tomber les épinards dans une poêle chaude. Sers le saumon sur le quinoa avec les épinards à côté." },
    it: { title: "Salmone e quinoa", steps: "Preriscalda il forno a 200 °C. Disponi il salmone su una teglia foderata, condiscilo con olio d'oliva e una spruzzata di limone e cuoci in forno circa 12 minuti finché si sfalda facilmente. Nel frattempo cuoci la quinoa e fai appassire gli spinaci in una padella calda. Servi il salmone sulla quinoa con gli spinaci a lato." },
  },
  r20: {
    de: { title: "Eier-Kartoffel-Salat", steps: "Koche die Eier und gewürfelte Kartoffeln, bis beides gerade gar ist, dann abkühlen lassen und die Eier pellen. Hacke die Eier grob und vermenge sie mit den Kartoffeln, einem Löffel Mayonnaise und etwas Senf. Hebe alles vorsichtig unter, damit die Kartoffeln ihre Form behalten. Auf einem Bett aus Salatblättern servieren." },
    es: { title: "Ensalada de huevo y patata", steps: "Cuece los huevos y las patatas en dados hasta que ambos estén hechos, luego enfríalos y pela los huevos. Pica los huevos en trozos grandes y mézclalos con las patatas, una cucharada de mayonesa y un poco de mostaza. Remueve con cuidado para que las patatas mantengan su forma. Sirve sobre una cama de hojas de lechuga." },
    fr: { title: "Salade d'œufs et pommes de terre", steps: "Fais cuire les œufs et des pommes de terre en dés jusqu'à ce que les deux soient juste cuits, puis laisse refroidir et écale les œufs. Coupe grossièrement les œufs et mélange-les avec les pommes de terre, une cuillère de mayonnaise et un peu de moutarde. Mélange délicatement pour que les pommes de terre gardent leur forme. Sers sur un lit de feuilles de laitue." },
    it: { title: "Insalata di uova e patate", steps: "Lessa le uova e le patate a cubetti finché entrambe sono appena cotte, poi falle raffreddare e sguscia le uova. Taglia grossolanamente le uova e uniscile alle patate, un cucchiaio di maionese e un po' di senape. Mescola con delicatezza così le patate mantengono la forma. Servi su un letto di foglie di lattuga." },
  },
  r21: {
    de: { title: "Hähnchen-Gurken-Wrap", steps: "Bestreiche einen glutenfreien Wrap mit einer dünnen Schicht Mayonnaise. Lege ein paar Salatblätter in die Mitte, dann Gurkenscheiben und zerpflücktes gegartes Hähnchen darauf. Mit etwas Salz und Pfeffer würzen. Rolle den Wrap fest auf, schlage die Enden ein und halbiere ihn zum Servieren." },
    es: { title: "Wrap de pollo y pepino", steps: "Unta un wrap sin gluten con una capa fina de mayonesa. Coloca unas hojas de lechuga en el centro y añade pepino en rodajas y pollo cocido desmenuzado. Sazona con un poco de sal y pimienta. Enróllalo bien apretado, mete los extremos y córtalo por la mitad para servir." },
    fr: { title: "Wrap poulet-concombre", steps: "Tartine une galette sans gluten d'une fine couche de mayonnaise. Dispose quelques feuilles de laitue au centre, puis ajoute du concombre en rondelles et du poulet cuit effiloché. Assaisonne d'un peu de sel et de poivre. Roule bien serré, replie les extrémités et coupe en deux pour servir." },
    it: { title: "Wrap con pollo e cetriolo", steps: "Spalma una piadina senza glutine con un velo di maionese. Disponi qualche foglia di lattuga al centro, poi aggiungi cetriolo a fette e pollo cotto sfilacciato. Condisci con un po' di sale e pepe. Arrotola stretto, ripiega le estremità e taglia a metà per servire." },
  },
  r22: {
    de: { title: "Reis mit gebratenem Thunfisch", steps: "Koche den Reis und halte ihn warm. Tupfe ein Thunfischsteak trocken und brate es in etwas Olivenöl bei starker Hitze etwa 1 Minute pro Seite, damit es innen rosa bleibt. Schneide den Thunfisch in Scheiben und lege ihn mit Gurkenstreifen auf den Reis. Zum Schluss mit etwas Sojasauce beträufeln." },
    es: { title: "Arroz con atún sellado", steps: "Cuece el arroz y mantenlo caliente. Seca un filete de atún con papel y séllalo en un poco de aceite de oliva a fuego fuerte, aproximadamente 1 minuto por lado para que quede rosado por dentro. Corta el atún en láminas y colócalo sobre el arroz con tiras de pepino. Termina con un chorrito de salsa de soja." },
    fr: { title: "Riz et thon saisi", steps: "Cuis le riz et garde-le au chaud. Sèche un steak de thon et saisis-le dans un peu d'huile d'olive à feu vif, environ 1 minute par face pour qu'il reste rosé au centre. Tranche le thon et dispose-le sur le riz avec des rubans de concombre. Termine par un trait de sauce soja." },
    it: { title: "Riso e tonno scottato", steps: "Cuoci il riso e tienilo al caldo. Asciuga un trancio di tonno e scottalo in un po' di olio d'oliva a fuoco vivo, circa 1 minuto per lato così resta rosa all'interno. Affetta il tonno e disponilo sul riso con nastri di cetriolo. Completa con un goccio di salsa di soia." },
  },
  r23: {
    de: { title: "Kürbis-Feta-Salat", steps: "Heize den Ofen auf 200 °C vor. Vermenge gewürfelten Kürbis mit Olivenöl und röste ihn etwa 20 Minuten, bis er weich und leicht karamellisiert ist, und lass ihn etwas abkühlen. Gib ihn in eine Schüssel mit Salat, zerbröckeltem Feta und Sonnenblumenkernen. Mit Olivenöl beträufeln und vorsichtig durchmengen." },
    es: { title: "Ensalada de calabaza y feta", steps: "Precalienta el horno a 200 °C. Mezcla la calabaza en dados con aceite de oliva y ásala unos 20 minutos hasta que esté blanda y ligeramente caramelizada; deja que se enfríe un poco. Ponla en un bol con lechuga, feta desmenuzado y pipas de girasol. Riega con aceite de oliva y mezcla con cuidado." },
    fr: { title: "Salade de potiron et feta", steps: "Préchauffe le four à 200 °C. Mélange le potiron en dés avec de l'huile d'olive et fais-le rôtir environ 20 minutes jusqu'à ce qu'il soit tendre et légèrement caramélisé, puis laisse tiédir. Verse-le dans un saladier avec de la laitue, de la feta émiettée et des graines de tournesol. Arrose d'huile d'olive et mélange délicatement." },
    it: { title: "Insalata di zucca e feta", steps: "Preriscalda il forno a 200 °C. Condisci la zucca a cubetti con olio d'oliva e arrostiscila circa 20 minuti finché è morbida e leggermente caramellata, poi falla intiepidire. Versala in una ciotola con lattuga, feta sbriciolata e semi di girasole. Irrora con olio d'oliva e mescola con delicatezza." },
  },
  r24: {
    de: { title: "Schweinefleisch-Reis-Bowl", steps: "Koche den Reis und halte ihn warm. Reibe etwas frischen Ingwer und brate dünn geschnittenes Schweinefleisch damit in einer heißen Pfanne gar. Dämpfe oder koche die Karotten, bis sie gerade weich sind. Serviere Fleisch und Karotten auf dem Reis mit etwas Sojasauce." },
    es: { title: "Bol de cerdo y arroz", steps: "Cuece el arroz y mantenlo caliente. Ralla un poco de jengibre fresco y saltea el cerdo en tiras finas con él en una sartén caliente hasta que esté hecho. Cuece al vapor o hierve ligeramente las zanahorias hasta que estén tiernas. Sirve el cerdo y las zanahorias sobre el arroz con un chorrito de salsa de soja." },
    fr: { title: "Bol de porc et riz", steps: "Cuis le riz et garde-le au chaud. Râpe un peu de gingembre frais et fais sauter du porc émincé avec dans une poêle chaude jusqu'à ce qu'il soit cuit. Fais cuire les carottes à la vapeur ou à l'eau jusqu'à ce qu'elles soient tout juste tendres. Sers le porc et les carottes sur le riz avec un trait de sauce soja." },
    it: { title: "Bowl di maiale e riso", steps: "Cuoci il riso e tienilo al caldo. Grattugia un po' di zenzero fresco e salta il maiale a fette sottili con quello in una padella calda finché è cotto. Cuoci a vapore o lessa leggermente le carote finché sono appena tenere. Servi maiale e carote sul riso con un goccio di salsa di soia." },
  },
  r25: {
    de: { title: "Caprese mit Oliven", steps: "Schneide frischen Mozzarella und Tomate in Scheiben und richte sie abwechselnd auf einem Teller an. Streue ein paar Oliven darüber. Großzügig mit Olivenöl beträufeln und nach Geschmack salzen. Bei Zimmertemperatur servieren – Kälte dämpft das Aroma." },
    es: { title: "Caprese con aceitunas", steps: "Corta en rodajas mozzarella fresca y tomate y colócalos alternados en un plato. Reparte unas aceitunas por encima. Riega generosamente con aceite de oliva y sala al gusto. Sirve a temperatura ambiente: el frío apaga el sabor." },
    fr: { title: "Caprese aux olives", steps: "Tranche de la mozzarella fraîche et de la tomate et dispose-les en alternance dans une assiette. Parsème de quelques olives. Arrose généreusement d'huile d'olive et sale selon ton goût. Sers à température ambiante : le froid atténue les saveurs." },
    it: { title: "Caprese con olive", steps: "Affetta mozzarella fresca e pomodoro e disponili alternati su un piatto. Distribuisci qualche oliva sopra. Condisci generosamente con olio d'oliva e sala a piacere. Servi a temperatura ambiente: il freddo attenua il sapore." },
  },
  r26: {
    de: { title: "Rindfleisch-Reisnudel-Pfanne", steps: "Koche die Reisnudeln, gieße sie ab und stell sie beiseite. Brate dünn geschnittenes Rindfleisch und geputzte grüne Bohnen in knoblaucharomatisiertem Öl bei starker Hitze mit etwas geriebenem Ingwer, bis das Fleisch braun und die Bohnen bissfest sind. Gib die Nudeln und einen kräftigen Schuss Sojasauce dazu. Alles eine Minute über der Hitze durchschwenken und servieren." },
    es: { title: "Salteado de ternera con fideos de arroz", steps: "Cuece los fideos de arroz, escúrrelos y resérvalos. Saltea la ternera en tiras finas y las judías verdes limpias en aceite con infusión de ajo a fuego fuerte con un poco de jengibre rallado, hasta que la carne se dore y las judías queden al dente. Añade los fideos y un buen chorro de salsa de soja. Saltea todo un minuto al fuego y sirve." },
    fr: { title: "Sauté de bœuf aux nouilles de riz", steps: "Cuis les nouilles de riz, puis égoutte-les et réserve. Fais sauter du bœuf émincé et des haricots verts équeutés dans de l'huile à l'ail à feu vif avec un peu de gingembre râpé, jusqu'à ce que le bœuf soit doré et les haricots croquants. Ajoute les nouilles et un bon trait de sauce soja. Fais sauter le tout une minute sur le feu et sers." },
    it: { title: "Saltato di manzo e noodle di riso", steps: "Cuoci i noodle di riso, poi scolali e mettili da parte. Salta il manzo a fette sottili e i fagiolini mondati in olio aromatizzato all'aglio a fuoco vivo con un po' di zenzero grattugiato, finché la carne è rosolata e i fagiolini restano croccanti. Aggiungi i noodle e un bel goccio di salsa di soia. Fai saltare il tutto un minuto sul fuoco e servi." },
  },
  r27: {
    de: { title: "Gebackener Lachs mit Kartoffeln", steps: "Heize den Ofen auf 200 °C vor. Vermenge gewürfelte Kartoffeln mit Olivenöl, Salz und Pfeffer, verteile sie auf einem Blech und röste sie 10 Minuten vor. Lege das Lachsfilet mit der Hautseite nach unten dazu, würze es und backe weitere 12–15 Minuten, bis es sich leicht zerteilen lässt. Lass währenddessen den Grünkohl in einer heißen Pfanne mit etwas Öl 2–3 Minuten zusammenfallen. Alles anrichten und den Lachs kräftig mit Zitrone beträufeln." },
    es: { title: "Salmón al horno con patatas", steps: "Precalienta el horno a 200 °C. Mezcla las patatas en dados con aceite de oliva, sal y pimienta, extiéndelas en una bandeja y ásalas 10 minutos para adelantarlas. Añade el lomo de salmón con la piel hacia abajo, sazónalo y hornea otros 12–15 minutos hasta que se desmenuce con facilidad. Mientras, saltea la col rizada en una sartén caliente con un poco de aceite 2–3 minutos. Emplata todo y exprime bien limón sobre el salmón." },
    fr: { title: "Saumon au four et pommes de terre", steps: "Préchauffe le four à 200 °C. Mélange les pommes de terre en dés avec de l'huile d'olive, du sel et du poivre, étale-les sur une plaque et fais-les rôtir 10 minutes pour les précuire. Ajoute le pavé de saumon côté peau vers le bas, assaisonne et enfourne encore 12 à 15 minutes jusqu'à ce qu'il se détache facilement. Pendant ce temps, fais tomber le chou kale dans une poêle chaude avec un peu d'huile 2 à 3 minutes. Dresse le tout et presse bien du citron sur le saumon." },
    it: { title: "Salmone al forno con patate", steps: "Preriscalda il forno a 200 °C. Condisci le patate a cubetti con olio d'oliva, sale e pepe, stendile su una teglia e arrostiscile 10 minuti per portarle avanti. Aggiungi il filetto di salmone con la pelle verso il basso, condiscilo e cuoci altri 12–15 minuti finché si sfalda facilmente. Nel frattempo fai appassire il cavolo riccio in una padella calda con un po' d'olio per 2–3 minuti. Impiatta il tutto e spremi bene del limone sul salmone." },
  },
  r28: {
    de: { title: "Hähnchen und Reis mit Karotten", steps: "Heize den Ofen auf 200 °C vor. Reibe Hähnchenschenkel mit etwas knoblaucharomatisiertem Öl, Salz und Pfeffer ein und lege sie mit den Karotten in eine Bratform. Röste sie etwa 25 Minuten, bis das Hähnchen goldbraun und gar ist. Koche währenddessen den Reis. Serviere Hähnchen und Karotten auf dem Reis und träufle den Bratensaft darüber." },
    es: { title: "Pollo y arroz con zanahorias", steps: "Precalienta el horno a 200 °C. Unta los muslos de pollo con un poco de aceite con infusión de ajo, sal y pimienta y colócalos en una fuente con las zanahorias. Ásalos unos 25 minutos hasta que el pollo esté dorado y hecho. Mientras, cuece el arroz. Sirve el pollo y las zanahorias sobre el arroz, regando con los jugos de la fuente." },
    fr: { title: "Poulet et riz aux carottes", steps: "Préchauffe le four à 200 °C. Frotte des cuisses de poulet avec un peu d'huile à l'ail, du sel et du poivre et place-les dans un plat avec les carottes. Fais rôtir environ 25 minutes jusqu'à ce que le poulet soit doré et cuit. Pendant ce temps, cuis le riz. Sers le poulet et les carottes sur le riz en nappant du jus de cuisson." },
    it: { title: "Pollo e riso con carote", steps: "Preriscalda il forno a 200 °C. Massaggia le cosce di pollo con un po' di olio aromatizzato all'aglio, sale e pepe e mettile in una teglia con le carote. Arrostisci circa 25 minuti finché il pollo è dorato e cotto. Nel frattempo cuoci il riso. Servi pollo e carote sul riso, irrorando con il fondo di cottura." },
  },
  r29: {
    de: { title: "Pasta mit Pesto (glutenfrei)", steps: "Koche die glutenfreie Pasta in Salzwasser bissfest, gieße sie ab und hebe etwas Kochwasser auf. Gib die Pasta zurück in den Topf und vermenge sie mit Basilikumpesto, bei Bedarf mit einem Schuss Kochwasser lockern. Halbiere die Kirschtomaten (bis zu 75 g) und hebe sie unter. Mit geriebenem Parmesan servieren." },
    es: { title: "Pasta con pesto (sin gluten)", steps: "Cuece la pasta sin gluten en agua con sal hasta que esté al dente, escúrrela y reserva un poco del agua de cocción. Devuelve la pasta a la olla y mézclala con pesto de albahaca, aflojándola con un chorrito del agua reservada si hace falta. Parte los tomates cherry por la mitad (hasta 75 g) e incorpóralos. Sirve con parmesano rallado por encima." },
    fr: { title: "Pâtes au pesto (sans gluten)", steps: "Cuis les pâtes sans gluten dans de l'eau salée jusqu'à ce qu'elles soient al dente, puis égoutte-les en gardant un peu d'eau de cuisson. Remets les pâtes dans la casserole et mélange-les au pesto de basilic, en détendant avec un peu d'eau réservée si besoin. Coupe les tomates cerises en deux (jusqu'à 75 g) et incorpore-les. Sers avec du parmesan râpé dessus." },
    it: { title: "Pasta al pesto (senza glutine)", steps: "Cuoci la pasta senza glutine in acqua salata al dente, poi scolala tenendo da parte un po' di acqua di cottura. Rimetti la pasta nella pentola e mescolala con il pesto al basilico, allentando con un goccio di acqua tenuta da parte se serve. Taglia i pomodorini a metà (fino a 75 g) e incorporali. Servi con parmigiano grattugiato sopra." },
  },
  r30: {
    de: { title: "Garnelen-Zucchini-Pfanne", steps: "Koche den Reis und halte ihn warm. Reibe etwas Ingwer und brate die Garnelen damit in knoblaucharomatisiertem Öl bei starker Hitze rosa, 2–3 Minuten, und nimm sie heraus. Gib gewürfelte Zucchini (etwa 65 g pro Portion) in die Pfanne und brate sie, bis sie gerade weich ist. Gib die Garnelen zurück, füge einen Schuss Sojasauce hinzu und serviere alles auf dem Reis." },
    es: { title: "Salteado de gambas y calabacín", steps: "Cuece el arroz y mantenlo caliente. Ralla un poco de jengibre y saltea las gambas con él en aceite con infusión de ajo a fuego fuerte hasta que estén rosadas, 2–3 minutos, y retíralas. Añade el calabacín en dados (unos 65 g por ración) a la sartén y saltéalo hasta que esté tierno. Devuelve las gambas, añade un chorrito de salsa de soja y sirve todo sobre el arroz." },
    fr: { title: "Sauté de crevettes et courgette", steps: "Cuis le riz et garde-le au chaud. Râpe un peu de gingembre et fais sauter les crevettes avec dans de l'huile à l'ail à feu vif jusqu'à ce qu'elles soient roses, 2 à 3 minutes, puis retire-les. Ajoute la courgette en dés (environ 65 g par portion) dans la poêle et fais-la sauter jusqu'à ce qu'elle soit tendre. Remets les crevettes, ajoute un trait de sauce soja et sers le tout sur le riz." },
    it: { title: "Saltato di gamberi e zucchine", steps: "Cuoci il riso e tienilo al caldo. Grattugia un po' di zenzero e salta i gamberi con quello in olio aromatizzato all'aglio a fuoco vivo finché sono rosati, 2–3 minuti, poi togline. Aggiungi la zucchina a dadini (circa 65 g a porzione) nella padella e saltala finché è appena tenera. Rimetti i gamberi, aggiungi un goccio di salsa di soia e servi il tutto sul riso." },
  },
  r31: {
    de: { title: "Rindfleisch-Kartoffel-Eintopf", steps: "Brate die Rindfleischstücke in etwas Olivenöl in einem schweren Topf bei mittlerer bis hoher Hitze portionsweise an, damit sie Farbe nehmen statt zu dünsten. Gib gewürfelte Kartoffeln und Karotten, einen Löffel knoblaucharomatisiertes Öl und so viel Wasser dazu, dass alles gerade bedeckt ist. Zum Köcheln bringen, zudecken und etwa 45 Minuten sanft garen, bis das Fleisch weich und die Sauce eingedickt ist. Vor dem Servieren abschmecken." },
    es: { title: "Estofado de ternera y patata", steps: "Dora los trozos de ternera en un poco de aceite de oliva en una olla pesada a fuego medio-alto, por tandas para que se doren en lugar de cocerse al vapor. Añade patatas y zanahorias en dados, una cucharada de aceite con infusión de ajo y agua justa para cubrir. Lleva a fuego lento, tapa y cuece suavemente unos 45 minutos hasta que la carne esté tierna y la salsa haya espesado. Rectifica de sal antes de servir." },
    fr: { title: "Ragoût de bœuf et pommes de terre", steps: "Fais dorer les morceaux de bœuf dans un peu d'huile d'olive dans une cocotte à feu moyen-vif, en plusieurs fois pour qu'ils colorent au lieu de bouillir. Ajoute des pommes de terre et des carottes en dés, une cuillère d'huile à l'ail et juste assez d'eau pour couvrir. Porte à frémissement, couvre et laisse mijoter doucement environ 45 minutes jusqu'à ce que le bœuf soit tendre et la sauce épaissie. Assaisonne avant de servir." },
    it: { title: "Spezzatino di manzo e patate", steps: "Rosola i pezzi di manzo in un po' di olio d'oliva in una pentola pesante a fuoco medio-alto, a più riprese così prendono colore invece di stufare. Aggiungi patate e carote a cubetti, un cucchiaio di olio aromatizzato all'aglio e acqua quanto basta a coprire. Porta a sobbollire, copri e cuoci dolcemente circa 45 minuti finché la carne è tenera e il sugo si è addensato. Aggiusta di sale prima di servire." },
  },
  r32: {
    de: { title: "Schweinebraten mit Grünkohl", steps: "Heize den Ofen auf 200 °C vor. Reibe das Schweinefleisch mit Senf, Salz und Pfeffer ein und lege es mit in Olivenöl gewendeten Kartoffelwürfeln in eine Bratform. Röste es etwa 25 Minuten, bis das Fleisch gar und die Kartoffeln goldbraun sind, und lass das Fleisch ein paar Minuten ruhen. Lass währenddessen den Grünkohl in einer heißen Pfanne mit etwas Olivenöl zusammenfallen. Schneide das Fleisch auf und serviere es mit Kartoffeln und Grünkohl." },
    es: { title: "Cerdo asado con col rizada", steps: "Precalienta el horno a 200 °C. Unta el cerdo con mostaza, sal y pimienta y colócalo en una fuente junto a patatas en dados mezcladas con aceite de oliva. Ásalo unos 25 minutos hasta que el cerdo esté hecho y las patatas doradas; deja reposar la carne unos minutos. Mientras, saltea la col rizada en una sartén caliente con un poco de aceite de oliva. Corta el cerdo y sírvelo con las patatas y la col." },
    fr: { title: "Rôti de porc et chou kale", steps: "Préchauffe le four à 200 °C. Frotte le porc de moutarde, sel et poivre et place-le dans un plat avec des pommes de terre en dés enrobées d'huile d'olive. Fais rôtir environ 25 minutes jusqu'à ce que le porc soit cuit et les pommes de terre dorées, puis laisse reposer la viande quelques minutes. Pendant ce temps, fais tomber le chou kale dans une poêle chaude avec un peu d'huile d'olive. Tranche le porc et sers-le avec les pommes de terre et le chou." },
    it: { title: "Arrosto di maiale con cavolo riccio", steps: "Preriscalda il forno a 200 °C. Massaggia il maiale con senape, sale e pepe e mettilo in una teglia insieme a patate a cubetti condite con olio d'oliva. Arrostisci circa 25 minuti finché il maiale è cotto e le patate dorate, poi fai riposare la carne qualche minuto. Nel frattempo fai appassire il cavolo riccio in una padella calda con un po' di olio d'oliva. Affetta il maiale e servilo con le patate e il cavolo." },
  },
  r33: {
    de: { title: "Weißfisch mit Reis und Bohnen", steps: "Koche den Reis und halte ihn warm. Brate ein Weißfischfilet in Olivenöl bei mittlerer Hitze 3–4 Minuten pro Seite mit einem Spritzer Zitrone, bis es sich leicht zerteilen lässt. Dämpfe währenddessen die grünen Bohnen, bis sie gerade weich sind. Serviere den Fisch auf dem Reis mit den Bohnen daneben und träufle den Bratensaft darüber." },
    es: { title: "Pescado blanco con arroz y judías", steps: "Cuece el arroz y mantenlo caliente. Fríe un filete de pescado blanco en aceite de oliva a fuego medio 3–4 minutos por lado con un chorro de limón, hasta que se desmenuce con facilidad. Mientras, cuece al vapor las judías verdes hasta que estén tiernas. Sirve el pescado sobre el arroz con las judías al lado y riega con los jugos de la sartén." },
    fr: { title: "Poisson blanc, riz et haricots", steps: "Cuis le riz et garde-le au chaud. Fais poêler un filet de poisson blanc dans l'huile d'olive à feu moyen 3 à 4 minutes par face avec un filet de citron, jusqu'à ce qu'il se détache facilement. Pendant ce temps, fais cuire les haricots verts à la vapeur jusqu'à ce qu'ils soient tendres. Sers le poisson sur le riz avec les haricots à côté et nappe du jus de cuisson." },
    it: { title: "Pesce bianco con riso e fagiolini", steps: "Cuoci il riso e tienilo al caldo. Cuoci in padella un filetto di pesce bianco in olio d'oliva a fuoco medio 3–4 minuti per lato con una spruzzata di limone, finché si sfalda facilmente. Nel frattempo cuoci a vapore i fagiolini finché sono appena teneri. Servi il pesce sul riso con i fagiolini a lato e irrora con il fondo di cottura." },
  },
  r34: {
    de: { title: "Putenbällchen mit Reis", steps: "Würze Putenhack mit Salz und Pfeffer und forme kleine Bällchen. Brate sie in etwas Olivenöl unter Wenden rundum braun und gar. Gib frisch gewürfelte Tomate und einen Löffel knoblaucharomatisiertes Öl dazu und lass alles 10 Minuten zu einer leichten Sauce köcheln. Auf Reis servieren und mit geriebenem Parmesan bestreuen." },
    es: { title: "Albóndigas de pavo con arroz", steps: "Sazona la carne picada de pavo con sal y pimienta y forma albóndigas pequeñas. Fríelas en un poco de aceite de oliva, dándoles la vuelta, hasta que estén doradas por fuera y hechas. Añade tomate fresco en dados y una cucharada de aceite con infusión de ajo y deja cocer 10 minutos hasta obtener una salsa ligera. Sirve sobre arroz con parmesano rallado por encima." },
    fr: { title: "Boulettes de dinde et riz", steps: "Assaisonne la dinde hachée de sel et de poivre et forme de petites boulettes. Fais-les revenir dans un peu d'huile d'olive, en les retournant, jusqu'à ce qu'elles soient dorées et cuites. Ajoute de la tomate fraîche en dés et une cuillère d'huile à l'ail et laisse mijoter 10 minutes en une sauce légère. Sers sur du riz avec du parmesan râpé dessus." },
    it: { title: "Polpette di tacchino e riso", steps: "Condisci il macinato di tacchino con sale e pepe e forma delle polpettine. Rosolale in un po' di olio d'oliva, girandole, finché sono dorate fuori e cotte. Aggiungi pomodoro fresco a dadini e un cucchiaio di olio aromatizzato all'aglio e lascia sobbollire 10 minuti in un sugo leggero. Servi sul riso con parmigiano grattugiato sopra." },
  },
  r35: {
    de: { title: "Tofu mit Reisnudeln", steps: "Presse festen Tofu (bis zu 170 g) aus, würfle ihn und tupfe ihn trocken. Brate ihn in etwas Öl rundum knusprig und goldbraun. Koche die Reisnudeln und vermenge sie mit dem Tofu, in Streifen geschnittener Karotte, einem Schuss Sojasauce und etwas geriebenem Ingwer. Warm servieren." },
    es: { title: "Tofu con fideos de arroz", steps: "Prensa y trocea tofu firme (hasta 170 g) y sécalo con papel. Fríelo en un poco de aceite hasta que esté crujiente y dorado por todos lados. Cuece los fideos de arroz y mézclalos con el tofu, zanahoria en tiras, un chorrito de salsa de soja y un poco de jengibre rallado. Sirve caliente." },
    fr: { title: "Tofu et nouilles de riz", steps: "Presse et coupe en dés du tofu ferme (jusqu'à 170 g) et sèche-le. Fais-le revenir dans un peu d'huile jusqu'à ce qu'il soit croustillant et doré sur toutes les faces. Cuis les nouilles de riz et mélange-les avec le tofu, de la carotte en julienne, un trait de sauce soja et un peu de gingembre râpé. Sers chaud." },
    it: { title: "Tofu e noodle di riso", steps: "Pressa e taglia a cubetti il tofu compatto (fino a 170 g) e asciugalo. Rosolalo in un po' d'olio finché è croccante e dorato su tutti i lati. Cuoci i noodle di riso e mescolali con il tofu, carota a listarelle, un goccio di salsa di soia e un po' di zenzero grattugiato. Servi caldo." },
  },
  r36: {
    de: { title: "Zitronen-Kräuter-Hähnchen mit Quinoa", steps: "Mariniere eine Hähnchenbrust ein paar Minuten in Zitronensaft, Olivenöl, Salz und Pfeffer. Brate sie bei mittlerer Hitze goldbraun und gar, etwa 6–8 Minuten, lass sie ruhen und schneide sie auf. Koche währenddessen die Quinoa und lass den Spinat in einer heißen Pfanne zusammenfallen. Serviere das Hähnchen auf der Quinoa mit dem Spinat daneben." },
    es: { title: "Pollo al limón con quinoa", steps: "Marina una pechuga de pollo unos minutos en zumo de limón, aceite de oliva, sal y pimienta. Fríela a fuego medio hasta que esté dorada y hecha, unos 6–8 minutos; déjala reposar y córtala. Mientras, cuece la quinoa y saltea las espinacas en una sartén caliente hasta que se ablanden. Sirve el pollo sobre la quinoa con las espinacas al lado." },
    fr: { title: "Poulet citron-herbes et quinoa", steps: "Fais mariner un blanc de poulet quelques minutes dans du jus de citron, de l'huile d'olive, du sel et du poivre. Fais-le revenir à feu moyen jusqu'à ce qu'il soit doré et cuit, environ 6 à 8 minutes, laisse-le reposer puis tranche-le. Pendant ce temps, cuis le quinoa et fais tomber les épinards dans une poêle chaude. Sers le poulet sur le quinoa avec les épinards à côté." },
    it: { title: "Pollo al limone con quinoa", steps: "Fai marinare un petto di pollo qualche minuto in succo di limone, olio d'oliva, sale e pepe. Rosolalo a fuoco medio finché è dorato e cotto, circa 6–8 minuti, fallo riposare e affettalo. Nel frattempo cuoci la quinoa e fai appassire gli spinaci in una padella calda. Servi il pollo sulla quinoa con gli spinaci a lato." },
  },
  r37: {
    de: { title: "Auberginen-Tomaten-Auflauf", steps: "Heize den Ofen auf 200 °C vor. Schneide die Aubergine (etwa 75 g pro Portion) und schichte sie in eine Auflaufform mit Tomatenscheiben und Mozzarella. Mit Olivenöl beträufeln und würzen. Etwa 25 Minuten backen, bis alles weich ist und Blasen wirft. Vor dem Servieren mit einem Löffel Pesto verfeinern." },
    es: { title: "Berenjena al horno con tomate", steps: "Precalienta el horno a 200 °C. Corta la berenjena (unos 75 g por ración) y colócala en capas en una fuente con tomate en rodajas y mozzarella. Riega con aceite de oliva y sazona. Hornea unos 25 minutos hasta que esté tierna y burbujeante. Termina con una cucharada de pesto antes de servir." },
    fr: { title: "Gratin d'aubergine et tomate", steps: "Préchauffe le four à 200 °C. Coupe l'aubergine (environ 75 g par portion) et dispose-la en couches dans un plat avec de la tomate en tranches et de la mozzarella. Arrose d'huile d'olive et assaisonne. Enfourne environ 25 minutes jusqu'à ce que ce soit fondant et bouillonnant. Termine par une cuillère de pesto avant de servir." },
    it: { title: "Melanzane al forno con pomodoro", steps: "Preriscalda il forno a 200 °C. Affetta la melanzana (circa 75 g a porzione) e disponila a strati in una pirofila con pomodoro a fette e mozzarella. Irrora con olio d'oliva e condisci. Cuoci in forno circa 25 minuti finché è morbida e sobbolle. Completa con un cucchiaio di pesto prima di servire." },
  },
  r38: {
    de: { title: "Buchweizen-Risotto", steps: "Röste den Buchweizen in etwas Olivenöl in einer Pfanne eine Minute an. Gib nach und nach heißes Wasser dazu und rühre, bis die Körner weich und cremig sind, etwa 20 Minuten. Rühre gegen Ende gewürfelte Karotte und Spinat unter, damit sie gar werden. Mit geriebenem Parmesan verfeinern und abschmecken." },
    es: { title: "Risotto de trigo sarraceno", steps: "Tuesta el trigo sarraceno en un poco de aceite de oliva en una sartén durante un minuto. Añade agua caliente poco a poco, removiendo, hasta que los granos estén tiernos y cremosos, unos 20 minutos. Incorpora zanahoria en dados y espinacas hacia el final para que se cocinen. Termina con parmesano rallado y rectifica de sal." },
    fr: { title: "Risotto de sarrasin", steps: "Fais torréfier le sarrasin dans un peu d'huile d'olive dans une poêle pendant une minute. Ajoute de l'eau chaude petit à petit, en remuant, jusqu'à ce que les grains soient tendres et crémeux, environ 20 minutes. Incorpore de la carotte en dés et des épinards vers la fin pour qu'ils cuisent. Termine avec du parmesan râpé et assaisonne." },
    it: { title: "Risotto di grano saraceno", steps: "Tosta il grano saraceno in un po' di olio d'oliva in una padella per un minuto. Aggiungi acqua calda poco alla volta, mescolando, finché i chicchi sono teneri e cremosi, circa 20 minuti. Verso la fine unisci carota a dadini e spinaci così cuociono. Manteca con parmigiano grattugiato e aggiusta di sale." },
  },
  r39: {
    de: { title: "Bratwurst mit Sauerkraut-Alternative", steps: "Brate die Bratwurst (bis zu 100 g) bei mittlerer Hitze unter Wenden braun und gar. Koche ein paar Kartoffeln weich. Brate fein geschnittenen Weißkohl (bis zu 75 g) in etwas Öl leicht an – als FODMAP-arme Alternative zu Sauerkraut. Serviere die Wurst mit den Kartoffeln, dem Kohl und einem Löffel Senf." },
    es: { title: "Bratwurst con alternativa al chucrut", steps: "Fríe la bratwurst (hasta 100 g) a fuego medio, dándole la vuelta, hasta que esté dorada y hecha. Cuece unas patatas hasta que estén tiernas. Saltea ligeramente col blanca en juliana (hasta 75 g) en un poco de aceite, como alternativa baja en FODMAP al chucrut. Sirve la salchicha con las patatas, la col y una cucharada de mostaza." },
    fr: { title: "Bratwurst et alternative à la choucroute", steps: "Fais revenir la bratwurst (jusqu'à 100 g) à feu moyen, en la retournant, jusqu'à ce qu'elle soit dorée et cuite. Fais cuire quelques pommes de terre jusqu'à ce qu'elles soient tendres. Fais revenir légèrement du chou blanc émincé (jusqu'à 75 g) dans un peu d'huile, en alternative pauvre en FODMAP à la choucroute. Sers la saucisse avec les pommes de terre, le chou et une cuillère de moutarde." },
    it: { title: "Bratwurst con alternativa ai crauti", steps: "Rosola la bratwurst (fino a 100 g) a fuoco medio, girandola, finché è dorata e cotta. Lessa qualche patata finché è tenera. Salta leggermente del cavolo cappuccio a listarelle (fino a 75 g) in un po' d'olio, come alternativa a basso contenuto di FODMAP ai crauti. Servi la salsiccia con le patate, il cavolo e un cucchiaio di senape." },
  },
  r40: {
    de: { title: "Lachs mit Zucchini-Nudeln", steps: "Schneide die Zucchini (bis zu 65 g pro Portion) mit einem Spiralschneider zu Nudeln. Brate sie kurz in etwas Olivenöl an, damit sie bissfest bleiben, 1–2 Minuten. Backe oder brate währenddessen den Lachs, bis er sich leicht zerteilen lässt. Toppe die Zucchini-Nudeln mit dem Lachs, einem Spritzer Zitrone und einem Löffel Pesto." },
    es: { title: "Salmón con noodles de calabacín", steps: "Corta el calabacín (hasta 65 g por ración) en espiral para hacer noodles. Saltéalos brevemente en un poco de aceite de oliva para que queden firmes, 1–2 minutos. Mientras, hornea o fríe el salmón hasta que se desmenuce. Cubre los noodles de calabacín con el salmón, un chorro de limón y una cucharada de pesto." },
    fr: { title: "Saumon et nouilles de courgette", steps: "Transforme la courgette (jusqu'à 65 g par portion) en nouilles au spiraliseur. Fais-les sauter brièvement dans un peu d'huile d'olive pour qu'elles restent fermes, 1 à 2 minutes. Pendant ce temps, cuis le saumon au four ou à la poêle jusqu'à ce qu'il se détache. Garnis les nouilles de courgette de saumon, d'un filet de citron et d'une cuillère de pesto." },
    it: { title: "Salmone e spaghetti di zucchine", steps: "Riduci la zucchina (fino a 65 g a porzione) in spaghetti con lo spiralizzatore. Saltali brevemente in un po' di olio d'oliva così restano sodi, 1–2 minuti. Nel frattempo cuoci il salmone al forno o in padella finché si sfalda. Completa gli spaghetti di zucchine con il salmone, una spruzzata di limone e un cucchiaio di pesto." },
  },
  r41: {
    de: { title: "Spaghetti aglio e olio (glutenfrei)", steps: "Koche die glutenfreien Spaghetti in gut gesalzenem Wasser bissfest, gieße sie ab und hebe etwas Nudelwasser auf. Erwärme reichlich knoblaucharomatisiertes Olivenöl in einer Pfanne bei niedriger Hitze, damit es nicht verbrennt. Schwenke die abgetropfte Pasta im Öl mit einem Schuss Nudelwasser, damit alles bindet. Mit geriebenem Parmesan und frisch gemahlenem schwarzem Pfeffer vollenden." },
    es: { title: "Espaguetis aglio e olio (sin gluten)", steps: "Cuece los espaguetis sin gluten en agua bien salada hasta que estén al dente, escúrrelos y reserva un poco del agua de cocción. Calienta bastante aceite de oliva con infusión de ajo en una sartén a fuego bajo para que no se queme. Saltea la pasta escurrida en el aceite con un chorrito del agua reservada para ligarla. Termina con parmesano rallado y una buena vuelta de pimienta negra." },
    fr: { title: "Spaghettis aglio e olio (sans gluten)", steps: "Cuis les spaghettis sans gluten dans une eau bien salée jusqu'à ce qu'ils soient al dente, puis égoutte-les en gardant un peu d'eau de cuisson. Fais chauffer une bonne quantité d'huile d'olive à l'ail dans une poêle à feu doux pour qu'elle ne brûle pas. Fais sauter les pâtes égouttées dans l'huile avec un peu d'eau réservée pour les lier. Termine avec du parmesan râpé et un bon tour de poivre noir." },
    it: { title: "Spaghetti aglio e olio (senza glutine)", steps: "Cuoci gli spaghetti senza glutine in acqua ben salata al dente, poi scolali tenendo da parte un po' di acqua di cottura. Scalda abbondante olio d'oliva aromatizzato all'aglio in una padella a fuoco basso così non brucia. Salta la pasta scolata nell'olio con un goccio di acqua tenuta da parte per legare. Completa con parmigiano grattugiato e una bella macinata di pepe nero." },
  },
  r42: {
    de: { title: "Brathähnchen mit Kürbis", steps: "Heize den Ofen auf 200 °C vor. Schneide den Kürbis in Würfel und vermenge ihn mit knoblaucharomatisiertem Öl, Salz und Pfeffer. Lege Hähnchen und Kürbis in eine Bratform und röste sie etwa 35 Minuten, bis das Hähnchen goldbraun und gar und der Kürbis weich ist. Brate währenddessen den Grünkohl in einer heißen Pfanne, bis er zusammenfällt. Serviere das Hähnchen mit Kürbis und Grünkohl." },
    es: { title: "Pollo asado con calabaza", steps: "Precalienta el horno a 200 °C. Corta la calabaza en dados y mézclala con aceite con infusión de ajo, sal y pimienta. Coloca el pollo y la calabaza en una fuente y ásalos unos 35 minutos hasta que el pollo esté dorado y hecho y la calabaza tierna. Mientras, saltea la col rizada en una sartén caliente hasta que se ablande. Sirve el pollo con la calabaza y la col." },
    fr: { title: "Poulet rôti et potiron", steps: "Préchauffe le four à 200 °C. Coupe le potiron en dés et mélange-le avec de l'huile à l'ail, du sel et du poivre. Place le poulet et le potiron dans un plat et fais rôtir environ 35 minutes jusqu'à ce que le poulet soit doré et cuit et le potiron tendre. Pendant ce temps, fais revenir le chou kale dans une poêle chaude jusqu'à ce qu'il tombe. Sers le poulet avec le potiron et le chou." },
    it: { title: "Pollo arrosto con zucca", steps: "Preriscalda il forno a 200 °C. Taglia la zucca a cubetti e condiscila con olio aromatizzato all'aglio, sale e pepe. Metti pollo e zucca in una teglia e arrostisci circa 35 minuti finché il pollo è dorato e cotto e la zucca è morbida. Nel frattempo salta il cavolo riccio in una padella calda finché appassisce. Servi il pollo con la zucca e il cavolo." },
  },
  r43: {
    de: { title: "Karottensticks mit Knoblauchöl-Hummus-Alternative", steps: "Mixe Seidentofu mit einem Löffel knoblaucharomatisiertem Öl, einem Spritzer Zitrone und einer Prise Salz glatt und cremig – eine FODMAP-arme Alternative zu Hummus. Abschmecken und die Würze anpassen. Schneide die Karotten in Sticks. Serviere den Dip mit den Karottensticks zum Eintunken." },
    es: { title: "Bastones de zanahoria con alternativa al hummus", steps: "Bate tofu sedoso con una cucharada de aceite con infusión de ajo, un chorro de limón y una pizca de sal hasta que quede suave y cremoso: una alternativa baja en FODMAP al hummus. Prueba y ajusta la sazón. Corta las zanahorias en bastones. Sirve la salsa con los bastones de zanahoria para mojar." },
    fr: { title: "Bâtonnets de carotte et alternative au houmous", steps: "Mixe du tofu soyeux avec une cuillère d'huile à l'ail, un filet de citron et une pincée de sel jusqu'à obtenir une texture lisse et crémeuse : une alternative pauvre en FODMAP au houmous. Goûte et ajuste l'assaisonnement. Coupe les carottes en bâtonnets. Sers la sauce avec les bâtonnets de carotte pour tremper." },
    it: { title: "Bastoncini di carota con alternativa all'hummus", steps: "Frulla il tofu vellutato con un cucchiaio di olio aromatizzato all'aglio, una spruzzata di limone e un pizzico di sale fino a ottenere una crema liscia: un'alternativa all'hummus a basso contenuto di FODMAP. Assaggia e regola di sale. Taglia le carote a bastoncini. Servi la salsa con i bastoncini di carota da intingere." },
  },
  r44: {
    de: { title: "Reiswaffeln mit Erdnussbutter", steps: "Bestreiche ein paar Reiswaffeln gleichmäßig mit Erdnussbutter. Schäle eine feste (grüne) Banane und schneide sie in dünne Scheiben. Lege die Scheiben auf die Erdnussbutter. Iss gleich, damit die Reiswaffeln knusprig bleiben." },
    es: { title: "Tortitas de arroz con mantequilla de cacahuete", steps: "Extiende mantequilla de cacahuete de manera uniforme sobre un par de tortitas de arroz. Pela un plátano firme (verde) y córtalo en rodajas finas. Coloca las rodajas sobre la mantequilla de cacahuete. Cómelo enseguida para que las tortitas sigan crujientes." },
    fr: { title: "Galettes de riz au beurre de cacahuète", steps: "Étale du beurre de cacahuète uniformément sur deux galettes de riz. Épluche une banane ferme (verte) et coupe-la en fines rondelles. Dispose les rondelles sur le beurre de cacahuète. Déguste tout de suite pour que les galettes restent croustillantes." },
    it: { title: "Gallette di riso con burro di arachidi", steps: "Spalma il burro di arachidi in modo uniforme su un paio di gallette di riso. Sbuccia una banana soda (verde) e affettala sottile. Disponi le fette sul burro di arachidi. Mangia subito così le gallette restano croccanti." },
  },
  r45: {
    de: { title: "Käse mit Oliven", steps: "Schneide den Cheddar in kleine Würfel. Richte ihn mit ein paar Oliven und einer kleinen Handvoll Walnüsse auf einem Teller an. Das war's – ein schneller, FODMAP-armer Snackteller. Halte die Portionen klein, vor allem bei den Walnüssen." },
    es: { title: "Queso con aceitunas", steps: "Corta el cheddar en dados pequeños. Colócalo en un plato con unas aceitunas y un puñado pequeño de nueces. Eso es todo: un plato de picoteo rápido y bajo en FODMAP. Mantén las raciones moderadas, sobre todo las nueces." },
    fr: { title: "Fromage et olives", steps: "Coupe le cheddar en petits dés. Dispose-le dans une assiette avec quelques olives et une petite poignée de noix. C'est tout : une assiette apéritive rapide et pauvre en FODMAP. Garde des portions modérées, surtout pour les noix." },
    it: { title: "Formaggio e olive", steps: "Taglia il cheddar a cubetti piccoli. Disponilo su un piatto con qualche oliva e una piccola manciata di noci. Tutto qui: un piatto snack veloce e a basso contenuto di FODMAP. Mantieni porzioni contenute, soprattutto per le noci." },
  },
  r46: {
    de: { title: "Beeren-Joghurt-Becher", steps: "Gib laktosefreien Joghurt in einen Becher oder eine kleine Schale. Streue eine Handvoll Blaubeeren darüber. Für etwas Süße einen Schuss Ahornsirup dazugeben. Gleich essen." },
    es: { title: "Vaso de yogur con frutos rojos", steps: "Pon yogur sin lactosa en un vaso o bol pequeño. Reparte un puñado de arándanos por encima. Añade un chorrito de sirope de arce para un toque dulce. Cómelo enseguida." },
    fr: { title: "Verrine de yaourt aux fruits rouges", steps: "Verse du yaourt sans lactose dans un verre ou un petit bol. Parsème d'une poignée de myrtilles. Ajoute un filet de sirop d'érable pour une touche sucrée. Déguste tout de suite." },
    it: { title: "Coppa di yogurt ai frutti di bosco", steps: "Metti dello yogurt senza lattosio in un bicchiere o in una ciotolina. Distribuisci una manciata di mirtilli sopra. Aggiungi un filo di sciroppo d'acero per un tocco dolce. Mangia subito." },
  },
  r47: {
    de: { title: "Gurken-Feta-Häppchen", steps: "Schneide die Gurke in dicke Scheiben. Belege jede Scheibe mit etwas zerbröckeltem Feta. Mit einem kleinen Schuss Olivenöl und etwas Pfeffer verfeinern. Als kleine Häppchen servieren." },
    es: { title: "Bocaditos de pepino y feta", steps: "Corta el pepino en rodajas gruesas. Coloca sobre cada rodaja un poco de feta desmenuzado. Añade un pequeño chorrito de aceite de oliva y una vuelta de pimienta. Sirve como bocaditos." },
    fr: { title: "Bouchées concombre-feta", steps: "Coupe le concombre en rondelles épaisses. Garnis chaque rondelle d'un peu de feta émiettée. Ajoute un petit filet d'huile d'olive et un tour de poivre. Sers en petites bouchées." },
    it: { title: "Bocconcini di cetriolo e feta", steps: "Taglia il cetriolo a rondelle spesse. Guarnisci ogni rondella con un po' di feta sbriciolata. Aggiungi un piccolo filo di olio d'oliva e una macinata di pepe. Servi come bocconcini." },
  },
  r48: {
    de: { title: "Hartgekochte Eier mit Salz", steps: "Lass 2 Eier in kochendes Wasser gleiten und koche sie 9 Minuten für festes Eigelb, schrecke sie dann unter kaltem Wasser ab. Pelle und halbiere die Eier. Mit etwas Meersalz bestreuen und essen." },
    es: { title: "Huevos duros con sal", steps: "Introduce 2 huevos en agua hirviendo y cuécelos 9 minutos para que la yema quede firme; refréscalos bajo agua fría. Pela y parte los huevos por la mitad. Espolvorea un poco de sal marina y come." },
    fr: { title: "Œufs durs au sel", steps: "Plonge 2 œufs dans de l'eau bouillante et fais-les cuire 9 minutes pour des jaunes fermes, puis rafraîchis-les sous l'eau froide. Écale et coupe les œufs en deux. Saupoudre d'un peu de sel de mer et déguste." },
    it: { title: "Uova sode con sale", steps: "Cala 2 uova in acqua bollente e cuocile 9 minuti per un tuorlo sodo, poi raffreddale sotto l'acqua fredda. Sguscia e taglia a metà le uova. Cospargi con un po' di sale marino e mangia." },
  },
  r49: {
    de: { title: "Zartbitterschokolade mit Walnüssen", steps: "Brich etwa 30 g Zartbitterschokolade (85 % oder mehr) ab. Serviere sie mit einer kleinen Handvoll Walnüsse. Langsam als sättigende, FODMAP-arme Nascherei genießen." },
    es: { title: "Chocolate negro con nueces", steps: "Parte unos 30 g de chocolate negro (85 % o más). Sírvelo con un puñado pequeño de nueces. Disfrútalo despacio como un capricho saciante y bajo en FODMAP." },
    fr: { title: "Chocolat noir et noix", steps: "Casse environ 30 g de chocolat noir (85 % ou plus). Sers-le avec une petite poignée de noix. Savoure lentement en encas rassasiant et pauvre en FODMAP." },
    it: { title: "Cioccolato fondente con noci", steps: "Spezza circa 30 g di cioccolato fondente (85% o più). Servilo con una piccola manciata di noci. Gustalo lentamente come uno sfizio saziante e a basso contenuto di FODMAP." },
  },
  r50: {
    de: { title: "Kürbiskern-Kiwi-Schale", steps: "Gib laktosefreien Joghurt in eine Schale. Schäle und schneide eine Kiwi und lege sie darauf. Streue einen Löffel Kürbiskerne für den Biss darüber. Gleich essen." },
    es: { title: "Bol de kiwi con pipas de calabaza", steps: "Pon yogur sin lactosa en un bol. Pela y corta un kiwi y colócalo por encima. Reparte una cucharada de pipas de calabaza para dar un toque crujiente. Cómelo enseguida." },
    fr: { title: "Bol de kiwi aux graines de courge", steps: "Verse du yaourt sans lactose dans un bol. Épluche et coupe un kiwi et dispose-le dessus. Parsème d'une cuillère de graines de courge pour le croquant. Déguste tout de suite." },
    it: { title: "Ciotola di kiwi con semi di zucca", steps: "Metti dello yogurt senza lattosio in una ciotola. Sbuccia e affetta un kiwi e disponilo sopra. Distribuisci un cucchiaio di semi di zucca per croccantezza. Mangia subito." },
  },
};

// { [foodId]: Array<{ [lang]: { name?: string; why?: string } }> }
// Reusable, localized "how to make it low-FODMAP" tips. Composed per high-FODMAP food
// (by its FODMAP groups + food category) to generate tailored guidance on the detail page.
export const LIGHTEN_TIPS: Record<string, { name: Record<string, string>; why: Record<string, string> }> = {
  alliums: {
    name: { en: "Onion & garlic → infused oil + green tops", de: "Zwiebel & Knoblauch → aromatisiertes Öl + grüne Spitzen", es: "Cebolla y ajo → aceite infusionado + parte verde", fr: "Oignon & ail → huile infusée + parties vertes", it: "Cipolla e aglio → olio aromatizzato + parte verde" },
    why: { en: "Onion and garlic are the main FODMAPs in most savoury dishes. Cook with garlic-infused oil and use only the green part of spring onion — the flavour stays, the fructans go.", de: "Zwiebel und Knoblauch sind die Haupt-FODMAPs in den meisten herzhaften Gerichten. Koche mit knoblaucharomatisiertem Öl und verwende nur den grünen Teil der Frühlingszwiebel — der Geschmack bleibt, die Fruktane nicht.", es: "La cebolla y el ajo son los principales FODMAP de la mayoría de los platos salados. Cocina con aceite con infusión de ajo y usa solo la parte verde de la cebolleta: el sabor se queda, los fructanos no.", fr: "L'oignon et l'ail sont les principaux FODMAP de la plupart des plats salés. Cuisine avec de l'huile à l'ail et n'utilise que la partie verte de l'oignon nouveau — la saveur reste, pas les fructanes.", it: "Cipolla e aglio sono i principali FODMAP nella maggior parte dei piatti salati. Cucina con olio aromatizzato all'aglio e usa solo la parte verde del cipollotto: il sapore resta, i fruttani no." },
  },
  wheat: {
    name: { en: "Wheat base → gluten-free", de: "Weizenbasis → glutenfrei", es: "Base de trigo → sin gluten", fr: "Base de blé → sans gluten", it: "Base di frumento → senza glutine" },
    why: { en: "The bread, pasta, wrapper or batter carries wheat fructans. A gluten-free version (rice, corn or GF flour) keeps the dish without them.", de: "Brot, Nudeln, Teighülle oder Panade enthalten Weizenfruktane. Eine glutenfreie Variante (Reis, Mais oder glutenfreies Mehl) behält das Gericht ohne sie.", es: "El pan, la pasta, la masa o el rebozado aportan fructanos de trigo. Una versión sin gluten (arroz, maíz o harina sin gluten) mantiene el plato sin ellos.", fr: "Le pain, les pâtes, la pâte ou la panure apportent des fructanes de blé. Une version sans gluten (riz, maïs ou farine sans gluten) garde le plat sans eux.", it: "Pane, pasta, sfoglia o pastella portano i fruttani del frumento. Una versione senza glutine (riso, mais o farina senza glutine) mantiene il piatto senza di essi." },
  },
  lactose: {
    name: { en: "Dairy → lactose-free or low-lactose cheese", de: "Milchprodukte → laktosefrei oder laktosearmer Käse", es: "Lácteos → sin lactosa o queso bajo en lactosa", fr: "Produits laitiers → sans lactose ou fromage pauvre en lactose", it: "Latticini → senza lattosio o formaggio a basso lattosio" },
    why: { en: "Use lactose-free milk or cream, or a naturally low-lactose cheese — mozzarella, parmesan and cheddar are all low-FODMAP in normal portions. Keep fresh soft cheeses like ricotta or cream cheese small.", de: "Verwende laktosefreie Milch oder Sahne oder einen von Natur aus laktosearmen Käse — Mozzarella, Parmesan und Cheddar sind in üblichen Portionen FODMAP-arm. Frischkäsesorten wie Ricotta oder Doppelrahm sparsam halten.", es: "Usa leche o nata sin lactosa, o un queso naturalmente bajo en lactosa: la mozzarella, el parmesano y el cheddar son bajos en FODMAP en raciones normales. Modera los quesos frescos como la ricota o el queso para untar.", fr: "Utilise du lait ou de la crème sans lactose, ou un fromage naturellement pauvre en lactose — la mozzarella, le parmesan et le cheddar sont pauvres en FODMAP en portions normales. Va doucement sur les fromages frais comme la ricotta ou le fromage à tartiner.", it: "Usa latte o panna senza lattosio, oppure un formaggio naturalmente povero di lattosio: mozzarella, parmigiano e cheddar sono low-FODMAP in porzioni normali. Modera i formaggi freschi come ricotta o formaggio spalmabile." },
  },
  gos: {
    name: { en: "Legumes → small, well-rinsed portion", de: "Hülsenfrüchte → kleine, gut gespülte Portion", es: "Legumbres → ración pequeña y bien enjuagada", fr: "Légumineuses → petite portion bien rincée", it: "Legumi → porzione piccola e ben sciacquata" },
    why: { en: "Beans, lentils and chickpeas are high in GOS. Use canned, well-rinsed legumes and keep the portion small — a lot of the GOS leaches into the water.", de: "Bohnen, Linsen und Kichererbsen sind reich an GOS. Nimm gut gespülte Hülsenfrüchte aus der Dose und halte die Portion klein — viel GOS geht ins Wasser über.", es: "Las alubias, lentejas y garbanzos son altos en GOS. Usa legumbres de bote bien enjuagadas y raciones pequeñas: gran parte del GOS pasa al agua.", fr: "Les haricots, lentilles et pois chiches sont riches en GOS. Utilise des légumineuses en conserve bien rincées et une petite portion — une grande partie du GOS passe dans l'eau.", it: "Fagioli, lenticchie e ceci sono ricchi di GOS. Usa legumi in scatola ben sciacquati e porzioni piccole: gran parte dei GOS passa nell'acqua." },
  },
  sweet_sauce: {
    name: { en: "Sweet sauce → low-FODMAP sweetener", de: "Süße Sauce → FODMAP-armer Süßstoff", es: "Salsa dulce → edulcorante bajo en FODMAP", fr: "Sauce sucrée → édulcorant pauvre en FODMAP", it: "Salsa dolce → dolcificante low-FODMAP" },
    why: { en: "The sweet glaze, sauce or filling is usually high in fructose (honey, high-fructose syrup). Make it with pure maple syrup or plain table sugar instead — both are low-FODMAP in normal amounts.", de: "Die süße Glasur, Sauce oder Füllung ist meist reich an Fruktose (Honig, Fruktosesirup). Nimm stattdessen reinen Ahornsirup oder normalen Haushaltszucker — beide sind in üblichen Mengen FODMAP-arm.", es: "El glaseado, la salsa o el relleno dulce suelen ser altos en fructosa (miel, jarabe de alta fructosa). Prepáralo con sirope de arce puro o azúcar de mesa normal: ambos son bajos en FODMAP en cantidades normales.", fr: "Le glaçage, la sauce ou la garniture sucrée est généralement riche en fructose (miel, sirop de fructose). Prépare-le plutôt avec du sirop d'érable pur ou du sucre de table ordinaire — tous deux pauvres en FODMAP en quantités normales.", it: "La glassa, la salsa o il ripieno dolce è di solito ricco di fruttosio (miele, sciroppo ad alto fruttosio). Preparalo con sciroppo d'acero puro o normale zucchero da tavola: entrambi sono low-FODMAP in quantità normali." },
  },
  fruit_swap: {
    name: { en: "Small portion, or a low-FODMAP fruit", de: "Kleine Portion oder eine FODMAP-arme Frucht", es: "Ración pequeña o una fruta baja en FODMAP", fr: "Petite portion ou un fruit pauvre en FODMAP", it: "Porzione piccola o un frutto low-FODMAP" },
    why: { en: "This fruit is high in excess fructose and/or polyols. A small serving may be tolerated, or swap for a low-FODMAP fruit like orange, kiwi, strawberry or firm banana.", de: "Diese Frucht ist reich an Überschuss-Fruktose und/oder Polyolen. Eine kleine Portion wird evtl. vertragen, oder wähle eine FODMAP-arme Frucht wie Orange, Kiwi, Erdbeere oder feste Banane.", es: "Esta fruta es alta en exceso de fructosa y/o polioles. Una ración pequeña puede tolerarse, o cámbiala por una fruta baja en FODMAP como naranja, kiwi, fresa o plátano firme.", fr: "Ce fruit est riche en excès de fructose et/ou en polyols. Une petite portion peut être tolérée, ou remplace-le par un fruit pauvre en FODMAP comme l'orange, le kiwi, la fraise ou la banane ferme.", it: "Questo frutto è ricco di fruttosio in eccesso e/o polioli. Una porzione piccola può essere tollerata, oppure scegli un frutto low-FODMAP come arancia, kiwi, fragola o banana soda." },
  },
  dried_fruit: {
    name: { en: "Just a small handful", de: "Nur eine kleine Handvoll", es: "Solo un puñado pequeño", fr: "Juste une petite poignée", it: "Solo una piccola manciata" },
    why: { en: "Drying concentrates the sugars, so dried fruit is high even in tiny amounts. Keep to about a tablespoon, or choose fresh low-FODMAP fruit.", de: "Trocknen konzentriert den Zucker, daher ist Trockenobst schon in kleinen Mengen hoch. Bleib bei etwa einem Esslöffel oder wähle frisches FODMAP-armes Obst.", es: "El secado concentra los azúcares, así que la fruta seca es alta incluso en cantidades pequeñas. Limítate a una cucharada o elige fruta fresca baja en FODMAP.", fr: "Le séchage concentre les sucres : les fruits secs sont élevés même en petite quantité. Limite-toi à une cuillère à soupe, ou choisis un fruit frais pauvre en FODMAP.", it: "L'essiccazione concentra gli zuccheri, quindi la frutta secca è alta anche in piccole quantità. Fermati a circa un cucchiaio, o scegli frutta fresca low-FODMAP." },
  },
  juice: {
    name: { en: "Whole low-FODMAP fruit instead", de: "Stattdessen ganze FODMAP-arme Frucht", es: "Mejor fruta entera baja en FODMAP", fr: "Plutôt un fruit entier pauvre en FODMAP", it: "Meglio un frutto intero low-FODMAP" },
    why: { en: "Juice concentrates the fruit sugars without the fibre that slows them down. A whole low-FODMAP fruit or water is gentler; if you do juice, keep the glass small.", de: "Saft konzentriert den Fruchtzucker ohne die Ballaststoffe, die ihn bremsen. Eine ganze FODMAP-arme Frucht oder Wasser ist schonender; wenn Saft, dann nur ein kleines Glas.", es: "El zumo concentra los azúcares de la fruta sin la fibra que los frena. Una fruta entera baja en FODMAP o agua sienta mejor; si tomas zumo, que el vaso sea pequeño.", fr: "Le jus concentre les sucres du fruit sans les fibres qui les ralentissent. Un fruit entier pauvre en FODMAP ou de l'eau est plus doux ; si tu prends du jus, garde un petit verre.", it: "Il succo concentra gli zuccheri della frutta senza le fibre che li rallentano. Un frutto intero low-FODMAP o dell'acqua è più delicato; se bevi succo, tieni il bicchiere piccolo." },
  },
  soft_drink: {
    name: { en: "Sugar-free or low-FODMAP drink", de: "Zuckerfreies oder FODMAP-armes Getränk", es: "Bebida sin azúcar o baja en FODMAP", fr: "Boisson sans sucre ou pauvre en FODMAP", it: "Bevanda senza zucchero o low-FODMAP" },
    why: { en: "Regular soft drinks are sweetened with high-fructose corn syrup. A sugar-free version, water, or a drink sweetened with plain sugar is low-FODMAP — just avoid ones with sorbitol or mannitol.", de: "Normale Softdrinks werden mit Fruktose-Glukose-Sirup gesüßt. Eine zuckerfreie Variante, Wasser oder ein mit normalem Zucker gesüßtes Getränk ist FODMAP-arm — meide nur solche mit Sorbit oder Mannit.", es: "Los refrescos normales llevan jarabe de maíz de alta fructosa. Una versión sin azúcar, agua o una bebida endulzada con azúcar normal es baja en FODMAP; solo evita las que llevan sorbitol o manitol.", fr: "Les sodas classiques sont sucrés au sirop de maïs à haute teneur en fructose. Une version sans sucre, de l'eau ou une boisson sucrée au sucre ordinaire est pauvre en FODMAP — évite juste celles avec sorbitol ou mannitol.", it: "Le bibite normali sono dolcificate con sciroppo di mais ad alto fruttosio. Una versione senza zucchero, acqua o una bevanda con zucchero normale è low-FODMAP; evita solo quelle con sorbitolo o mannitolo." },
  },
  soy_milk_swap: {
    name: { en: "Almond, rice or lactose-free milk", de: "Mandel-, Reis- oder laktosefreie Milch", es: "Leche de almendra, arroz o sin lactosa", fr: "Lait d'amande, de riz ou sans lactose", it: "Latte di mandorla, riso o senza lattosio" },
    why: { en: "Soy milk made from whole soybeans is high in GOS. Almond, rice, macadamia or lactose-free cow's milk are low-FODMAP (soy milk made from soy protein is usually fine too).", de: "Sojamilch aus ganzen Sojabohnen ist reich an GOS. Mandel-, Reis-, Macadamia- oder laktosefreie Kuhmilch sind FODMAP-arm (Sojamilch aus Sojaprotein ist meist auch okay).", es: "La leche de soja hecha con soja entera es alta en GOS. La de almendra, arroz, macadamia o la leche de vaca sin lactosa son bajas en FODMAP (la de soja hecha con proteína de soja suele estar bien).", fr: "Le lait de soja à base de graines entières est riche en GOS. Les laits d'amande, de riz, de macadamia ou le lait de vache sans lactose sont pauvres en FODMAP (le lait de soja à base de protéine de soja passe généralement bien aussi).", it: "Il latte di soia da fagioli interi è ricco di GOS. Mandorla, riso, macadamia o latte vaccino senza lattosio sono low-FODMAP (il latte di soia da proteine di soia di solito va bene)." },
  },
  tea_swap: {
    name: { en: "Peppermint or a low-FODMAP tea", de: "Pfefferminz- oder FODMAP-armer Tee", es: "Menta u otra infusión baja en FODMAP", fr: "Menthe poivrée ou un thé pauvre en FODMAP", it: "Menta o una tisana low-FODMAP" },
    why: { en: "Chamomile is high in fructans. Peppermint, green or black tea are low-FODMAP, and peppermint is especially calming for the gut.", de: "Kamille ist reich an Fruktanen. Pfefferminz-, Grün- oder Schwarztee sind FODMAP-arm, und Pfefferminze beruhigt den Darm besonders.", es: "La manzanilla es alta en fructanos. La menta, el té verde o el negro son bajos en FODMAP, y la menta calma especialmente el intestino.", fr: "La camomille est riche en fructanes. La menthe poivrée, le thé vert ou noir sont pauvres en FODMAP, et la menthe apaise particulièrement l'intestin.", it: "La camomilla è ricca di fruttani. Menta, tè verde o nero sono low-FODMAP, e la menta è particolarmente lenitiva per l'intestino." },
  },
  cereal_swap: {
    name: { en: "Oats or a low-FODMAP cereal", de: "Haferflocken oder FODMAP-armes Müsli", es: "Avena o un cereal bajo en FODMAP", fr: "Flocons d'avoine ou céréale pauvre en FODMAP", it: "Avena o un cereale low-FODMAP" },
    why: { en: "Wheat-bran and muesli/granola blends are high in fructans, and many add dried fruit and honey. Plain oats, cornflakes or rice-based cereal keep it low — check the label for added fruit.", de: "Weizenkleie und Müsli-/Granola-Mischungen sind reich an Fruktanen und enthalten oft Trockenobst und Honig. Reine Haferflocken, Cornflakes oder Reismüsli halten es niedrig — prüfe die Zutaten auf zugesetztes Obst.", es: "El salvado de trigo y las mezclas de muesli/granola son altos en fructanos, y muchos añaden fruta seca y miel. La avena, los copos de maíz o el cereal de arroz lo mantienen bajo; revisa la etiqueta por fruta añadida.", fr: "Le son de blé et les mélanges muesli/granola sont riches en fructanes, et beaucoup ajoutent fruits secs et miel. Les flocons d'avoine nature, les cornflakes ou les céréales de riz gardent le tout bas — vérifie l'étiquette pour les fruits ajoutés.", it: "La crusca di frumento e i mix muesli/granola sono ricchi di fruttani, e molti aggiungono frutta secca e miele. Fiocchi d'avena semplici, cornflakes o cereali di riso lo mantengono basso: controlla l'etichetta per la frutta aggiunta." },
  },
  fructan_veg: {
    name: { en: "Smaller portion or a low-FODMAP veg", de: "Kleinere Portion oder FODMAP-armes Gemüse", es: "Ración menor o una verdura baja en FODMAP", fr: "Portion réduite ou un légume pauvre en FODMAP", it: "Porzione ridotta o una verdura low-FODMAP" },
    why: { en: "The fructans here are dose-dependent. A small amount may be tolerated, or swap for a low-FODMAP vegetable like carrot, courgette, green beans or bell pepper.", de: "Die Fruktane hier sind dosisabhängig. Eine kleine Menge wird evtl. vertragen, oder wähle FODMAP-armes Gemüse wie Karotte, Zucchini, grüne Bohnen oder Paprika.", es: "Los fructanos aquí dependen de la dosis. Una cantidad pequeña puede tolerarse, o cámbialo por una verdura baja en FODMAP como zanahoria, calabacín, judías verdes o pimiento.", fr: "Les fructanes ici dépendent de la dose. Une petite quantité peut être tolérée, ou remplace par un légume pauvre en FODMAP comme carotte, courgette, haricots verts ou poivron.", it: "I fruttani qui dipendono dalla dose. Una piccola quantità può essere tollerata, oppure scegli una verdura low-FODMAP come carota, zucchina, fagiolini o peperone." },
  },
  polyol_veg: {
    name: { en: "Small portion or a low-FODMAP veg", de: "Kleine Portion oder FODMAP-armes Gemüse", es: "Ración pequeña o una verdura baja en FODMAP", fr: "Petite portion ou un légume pauvre en FODMAP", it: "Porzione piccola o una verdura low-FODMAP" },
    why: { en: "The polyols (sorbitol/mannitol) are dose-dependent — a small serving is often fine. Or swap for a low-FODMAP veg like carrot, courgette, spinach or bell pepper (and oyster mushrooms instead of button).", de: "Die Polyole (Sorbit/Mannit) sind dosisabhängig — eine kleine Portion ist oft okay. Oder wähle FODMAP-armes Gemüse wie Karotte, Zucchini, Spinat oder Paprika (und Austernpilze statt Champignons).", es: "Los polioles (sorbitol/manitol) dependen de la dosis: una ración pequeña suele ir bien. O cámbialo por una verdura baja en FODMAP como zanahoria, calabacín, espinaca o pimiento (y setas ostra en vez de champiñón).", fr: "Les polyols (sorbitol/mannitol) dépendent de la dose — une petite portion passe souvent bien. Ou remplace par un légume pauvre en FODMAP comme carotte, courgette, épinard ou poivron (et pleurotes au lieu de champignons de Paris).", it: "I polioli (sorbitolo/mannitolo) dipendono dalla dose: una porzione piccola spesso va bene. Oppure scegli una verdura low-FODMAP come carota, zucchina, spinaci o peperone (e funghi ostrica al posto degli champignon)." },
  },
  portion_generic: {
    name: { en: "Keep the portion small", de: "Portion klein halten", es: "Mantén la ración pequeña", fr: "Garde une petite portion", it: "Tieni la porzione piccola" },
    why: { en: "Most FODMAPs are dose-dependent — a smaller serving lowers the load. Pair it with clearly low-FODMAP foods instead of stacking several high ones in one meal.", de: "Die meisten FODMAPs sind dosisabhängig — eine kleinere Portion senkt die Last. Kombiniere sie mit klar FODMAP-armen Lebensmitteln, statt mehrere hohe in einer Mahlzeit zu stapeln.", es: "La mayoría de los FODMAP dependen de la dosis: una ración menor baja la carga. Combínalo con alimentos claramente bajos en FODMAP en vez de acumular varios altos en una comida.", fr: "La plupart des FODMAP dépendent de la dose — une portion plus petite réduit la charge. Associe-le à des aliments clairement pauvres en FODMAP plutôt que d'empiler plusieurs aliments élevés dans un repas.", it: "La maggior parte dei FODMAP dipende dalla dose: una porzione più piccola riduce il carico. Abbinalo ad alimenti chiaramente low-FODMAP invece di sommare più cibi alti nello stesso pasto." },
  },
};

